export function formatCurrency(amount) {
  return new Intl.NumberFormat('id-ID', {
    style: 'currency',
    currency: 'IDR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  }).format(amount);
}

export function formatNumber(num) {
  return new Intl.NumberFormat('id-ID').format(num);
}

export function formatDate(dateStr) {
  if (!dateStr) return '';
  
  const raw = String(dateStr);
  
  // Jika string sudah punya timezone info, parse langsung
  // Jika tidak, anggap sebagai UTC (sesuai backend SQLite CURRENT_TIMESTAMP)
  let date;
  if (/Z|[+-]\d{2}:?\d{2}$/.test(raw)) {
    date = new Date(raw);
  } else {
    // Format: 'YYYY-MM-DD HH:MM:SS' dari SQLite UTC
    // Parse sebagai UTC, lalu convert ke local time untuk display
    const isoStr = raw.replace(' ', 'T') + 'Z';
    date = new Date(isoStr);
  }

  if (isNaN(date.getTime())) return dateStr;

  // Format ke local timezone (WIB/WITA/WIT)
  return new Intl.DateTimeFormat('id-ID', {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZoneName: 'short'
  }).format(date);
}

export function formatShortDate(dateStr) {
  if (!dateStr) return '';
  const raw = String(dateStr);
  
  let date;
  if (/Z|[+-]\d{2}:?\d{2}$/.test(raw)) {
    date = new Date(raw);
  } else {
    // Parse sebagai UTC dari SQLite
    date = new Date(raw.replace(' ', 'T') + 'Z');
  }
  
  if (isNaN(date.getTime())) return dateStr;
  
  return new Intl.DateTimeFormat('id-ID', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }).format(date);
}

// Format number with thousand separator (for input display)
export function formatInputNumber(value) {
  // Remove non-digits
  const num = String(value).replace(/\D/g, '');
  if (!num) return '';
  return new Intl.NumberFormat('id-ID').format(parseInt(num));
}

// Parse formatted number back to integer
export function parseInputNumber(formattedValue) {
  if (!formattedValue) return 0;
  return parseInt(String(formattedValue).replace(/\D/g, '')) || 0;
}

// Setup auto-format for number input fields
export function setupNumberInput(inputId) {
  const input = document.getElementById(inputId);
  if (!input) return;

  input.addEventListener('input', (e) => {
    const cursorPos = e.target.selectionStart;
    const oldLength = e.target.value.length;
    const oldValue = e.target.value;

    // Format the value
    const formatted = formatInputNumber(e.target.value);
    e.target.value = formatted;

    // Adjust cursor position
    const newLength = formatted.length;
    // Hitung jumlah separator (titik) sebelum cursor di value lama vs baru
    const separatorsBefore = (oldValue.slice(0, cursorPos).match(/\./g) || []).length;
    const newRawPos = Math.max(0, cursorPos - separatorsBefore);

    // Hitung offset separator di formatted value sampai posisi raw yang sama
    let rawCount = 0;
    let newPos = 0;
    for (let i = 0; i < formatted.length; i++) {
      if (formatted[i] !== '.') rawCount++;
      if (rawCount >= newRawPos) { newPos = i + 1; break; }
    }

    e.target.setSelectionRange(newPos, newPos);
  });

  // Format initial value if exists
  if (input.value) {
    input.value = formatInputNumber(input.value);
  }
}

// Detect device info from User-Agent
export function getDeviceInfo() {
  const ua = navigator.userAgent;
  let device = 'Unknown Device';
  let browser = 'Unknown Browser';
  let os = 'Unknown OS';

  // Detect OS
  if (/Android/i.test(ua)) {
    os = 'Android';
    // Try to get device model
    const match = ua.match(/Android[^;]*;\s*([^)]+)/);
    if (match) {
      device = match[1].split('Build')[0].trim();
    }
  } else if (/iPhone|iPad|iPod/i.test(ua)) {
    os = 'iOS';
    if (/iPhone/i.test(ua)) device = 'iPhone';
    else if (/iPad/i.test(ua)) device = 'iPad';
    else device = 'iPod';
  } else if (/Windows/i.test(ua)) {
    os = 'Windows';
    device = 'PC';
  } else if (/Mac/i.test(ua)) {
    os = 'macOS';
    device = 'Mac';
  } else if (/Linux/i.test(ua)) {
    os = 'Linux';
    device = 'PC';
  }

  // Detect browser
  if (/Chrome/i.test(ua) && !/Edg/i.test(ua)) {
    browser = 'Chrome';
  } else if (/Safari/i.test(ua) && !/Chrome/i.test(ua)) {
    browser = 'Safari';
  } else if (/Firefox/i.test(ua)) {
    browser = 'Firefox';
  } else if (/Edg/i.test(ua)) {
    browser = 'Edge';
  } else if (/Opera|OPR/i.test(ua)) {
    browser = 'Opera';
  }

  return {
    device,
    browser,
    os,
    displayName: device !== 'Unknown Device' ? device : `${browser} on ${os}`
  };
}

// Helper for UI empty states
export function renderEmptyState(icon, message, ctaLabel = null, ctaAction = null) {
  return `
    <div class="empty-state-full">
      <div class="empty-icon">${icon}</div>
      <div class="empty-message">${message}</div>
      ${ctaLabel ? `<button class="btn btn-outline btn-sm" onclick="${ctaAction}">${ctaLabel}</button>` : ''}
    </div>
  `;
}

export function escapeHtml(str) {
  if (str == null) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}
