import { fetchCurrentUser, getApiServer, fetchSettings, updateSettings, fetchDeviceSessions, revokeDeviceSession } from '../services/api.js';
import { formatDate, getDeviceInfo, escapeHtml } from '../utils/format.js';
import { clearSavedServer } from '../utils/discovery.js';
import { logout } from '../utils/session.js';

let currentUser = null;

export async function ProfilePage() {
  const [user, settings] = await Promise.all([
    fetchCurrentUser(),
    fetchSettings()
  ]);

  currentUser = user;
  const sessionsData = await fetchDeviceSessions(user.id).catch(() => ({ sessions: [] }));
  const sessions = sessionsData.sessions || [];
  const deviceInfo = getDeviceInfo();

  const roleLabels = {
    admin: 'Administrator',
    supervisor: 'Supervisor',
    cashier: 'Kasir'
  };

  // Current device session from local storage
  const currentDeviceId = localStorage.getItem('pos_device_id');

  const isAdmin = user.role === 'admin';
  const sessionsHtml = renderSessionsList(sessions, user.id, currentDeviceId, isAdmin);

  return `
    <div class="page profile-page">
      <h2 class="page-title">Profil</h2>

      <!-- User Info Card -->
      <div class="profile-card">
        <div class="profile-avatar">
          ${escapeHtml(currentUser.fullName).charAt(0).toUpperCase()}
        </div>
        <div class="profile-info">
          <div class="profile-name">${escapeHtml(currentUser.fullName)}</div>
          <div class="profile-role-badge ${currentUser.role}">${roleLabels[currentUser.role] || currentUser.role}</div>
        </div>
      </div>

      <!-- User Details -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Informasi Akun</h3>
        </div>
        <div class="profile-details">
          <div class="detail-row">
            <span class="detail-label">Username</span>
            <span class="detail-value">${escapeHtml(currentUser.username)}</span>
          </div>
          <div class="detail-row">
            <span class="detail-label">Login Terakhir</span>
            <span class="detail-value">${currentUser.lastLogin ? formatDate(currentUser.lastLogin) : '-'}</span>
          </div>
          ${isAdmin ? `
          <div class="detail-row clickable" onclick="window.location.hash='/users'">
            <span class="detail-label">Aktivitas Login</span>
            <span class="detail-value">
              Lihat Semua
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <path d="M9 5l7 7-7 7"/>
              </svg>
            </span>
          </div>` : ''}
        </div>
      </div>

      <!-- Active Devices -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Perangkat Aktif</h3>
        </div>
        <div class="sessions-list" id="sessions-list">
          ${sessionsHtml}
        </div>
      </div>

      <!-- Server Connection -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Koneksi Server</h3>
        </div>
        <div class="settings-list">
          <div class="setting-item">
            <span class="setting-label">Server POS</span>
            <span class="setting-value" id="current-server">${getApiServer().host}:${getApiServer().port}</span>
          </div>
          <div class="setting-item">
            <div class="connection-status">
              <span class="status-dot online" id="connection-dot"></span>
              <span id="connection-text">Terhubung</span>
            </div>
            <button class="btn btn-sm btn-outline" onclick="rediscoverServer()">Ubah Server</button>
          </div>
        </div>
      </div>

      <!-- Settings -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Notifikasi</h3>
        </div>
        <div class="settings-list">
          <div class="setting-item">
            <label class="setting-label">Stok rendah</label>
            <label class="toggle">
              <input type="checkbox" checked id="notify-stock">
              <span class="toggle-slider"></span>
            </label>
          </div>
          <div class="setting-item">
            <label class="setting-label">Piutang jatuh tempo</label>
            <label class="toggle">
              <input type="checkbox" checked id="notify-debt">
              <span class="toggle-slider"></span>
            </label>
          </div>
          <div class="setting-item">
            <span class="setting-label">Zona Waktu (Timezone)</span>
            <select class="select-sm" id="select-timezone" onchange="updateTimezone(this.value)">
              <option value="7">WIB (UTC+7)</option>
              <option value="8">WITA (UTC+8)</option>
              <option value="9">WIT (UTC+9)</option>
            </select>
          </div>
        </div>
      </div>

      <!-- App Info -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Aplikasi</h3>
        </div>
        <div class="app-info">
          <div class="detail-row">
            <span class="detail-label">Versi</span>
            <span class="detail-value">1.0.0</span>
          </div>
          <div class="detail-row">
            <span class="detail-label">Platform</span>
            <span class="detail-value">PWA / Mobile</span>
          </div>
        </div>
        <div class="app-actions">
          <button class="btn btn-outline btn-block" onclick="clearCache()">Hapus Cache</button>
        </div>
      </div>

      <!-- Logout -->
      <div class="logout-section">
        <button class="btn btn-danger btn-block" onclick="handleLogout()">
          Keluar dari Akun
        </button>
      </div>
    </div>
  `;
}


function renderSessionsList(sessions, userId, currentDeviceId, isAdmin = false) {
  if (sessions.length === 0) {
    return '<div class="empty-state small">Belum ada data perangkat</div>';
  }
  return sessions.map(s => {
    const isCurrent = s.device_id === currentDeviceId;
    const lastSeen = s.last_seen
      ? new Date(s.last_seen).toLocaleString('id-ID', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })
      : '-';
    return `
      <div class="session-item ${isCurrent ? 'current' : ''}">
        <div class="session-info">
          <div class="session-device">${formatDeviceName(s.device_name)}</div>
          <div class="session-details">
            Terakhir aktif: ${lastSeen}
            ${isCurrent ? '<span class="current-badge">Perangkat Ini</span>' : ''}
          </div>
        </div>
        ${!isCurrent && isAdmin ? `<button class="btn btn-sm btn-danger" onclick="revokeSession(${userId}, ${s.id})">Cabut</button>` : ''}
      </div>
    `;
  }).join('');
}

function formatDeviceName(userAgent) {
  if (!userAgent) return 'Perangkat tidak dikenal';
  if (userAgent.includes('Android')) {
    const match = userAgent.match(/Android[^;)]*[;)]/);
    return 'Android - ' + (match ? match[0].replace(/[;)]/g, '').trim() : 'Mobile');
  }
  if (userAgent.includes('iPhone') || userAgent.includes('iPad')) return 'iOS - Safari';
  if (userAgent.includes('Windows')) return 'Windows - Browser';
  if (userAgent.includes('Mac')) return 'Mac - Browser';
  return userAgent.slice(0, 40) + '...';
}

function showConfirm(message, onConfirm) {
  const existing = document.getElementById('confirm-dialog');
  if (existing) existing.remove();

  const dialog = document.createElement('div');
  dialog.id = 'confirm-dialog';
  dialog.className = 'modal-overlay open';
  dialog.innerHTML = `
    <div class="product-modal-card">
      <div class="modal-body" style="padding: 24px 20px;">
        <p style="color: var(--text-main); font-size: 15px; line-height: 1.5;">${message}</p>
      </div>
      <div class="modal-footer">
        <button class="btn btn-outline" id="confirm-cancel">Batal</button>
        <button class="btn btn-danger" id="confirm-ok">Ya, Lanjutkan</button>
      </div>
    </div>
  `;
  document.body.appendChild(dialog);
  document.getElementById('confirm-cancel').onclick = () => dialog.remove();
  document.getElementById('confirm-ok').onclick = () => { dialog.remove(); onConfirm(); };
}

window.rediscoverServer = () => {
  showConfirm('Cari ulang server POS?<br>Aplikasi akan dimuat ulang.', () => {
    // Clear saved server and reload
    clearSavedServer();
    window.location.reload();
  });
};

window.clearCache = async () => {
  if ('caches' in window) {
    const names = await caches.keys();
    await Promise.all(names.map(name => caches.delete(name)));
    window.showToast?.('Cache berhasil dihapus', 'success');
  }
};

window.handleLogout = () => {
  showConfirm('Keluar dari akun?', () => logout());
};


window.updateTimezone = async (val) => {
  try {
    const offset = parseFloat(val);
    await updateSettings({ timezone_offset: offset });
    window.showToast?.('Zona waktu berhasil disimpan', 'success');
  } catch (e) {
    window.showToast?.('Gagal menyimpan zona waktu: ' + e.message, 'error');
  }
};

window.initProfile = async () => {
  // Set initial timezone value
  try {
    const settings = await fetchSettings();
    const select = document.getElementById('select-timezone');
    if (select && settings.timezone_offset) {
      select.value = settings.timezone_offset;
    } else if (select) {
      // Default to 7 if not set
      select.value = "7";
    }
  } catch (e) {
    console.error('Error init profile settings', e);
  }
};

window.revokeSession = async (userId, sessionId) => {
  if (currentUser?.role !== 'admin') {
    window.showToast?.('Hanya admin yang dapat mencabut akses perangkat', 'error');
    return;
  }
  showConfirm('Cabut akses perangkat ini?', async () => {
    try {
      await revokeDeviceSession(userId, sessionId);
      const sessionsData = await fetchDeviceSessions(userId).catch(() => ({ sessions: [] }));
      const currentDeviceId = localStorage.getItem('pos_device_id');
      document.getElementById('sessions-list').innerHTML = renderSessionsList(
        sessionsData.sessions || [],
        userId,
        currentDeviceId,
        true
      );
      window.showToast?.('Akses perangkat dicabut', 'success');
    } catch (err) {
      window.showToast?.('Gagal mencabut akses: ' + err.message, 'error');
    }
  });
};
