// Login Page
import { loginUser } from '../services/api.js';
import { saveSession } from '../utils/session.js';

export function LoginPage() {
  const config = window.APP_CONFIG || { name: 'POS Admin', logo: null, tagline: 'Masuk untuk mengelola toko Anda' };
  const appName = config.name;
  const tagline = config.tagline || 'Masuk untuk mengelola toko Anda';

  return `
    <div class="login-page">
      <div class="login-container">
        <div class="login-logo">
          ${config.logo ? `
            <img src="${config.logo}" alt="Logo" style="width: 80px; height: 80px; object-fit: contain;">
          ` : `
            <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <rect x="2" y="3" width="20" height="14" rx="2" ry="2"/>
              <line x1="8" y1="21" x2="16" y2="21"/>
              <line x1="12" y1="17" x2="12" y2="21"/>
            </svg>
          `}
        </div>
        <h1 class="login-title">${appName}</h1>
        <p class="login-subtitle">${tagline}</p>

        <form id="login-form" class="login-form">
          <div class="form-group">
            <label for="username">Username</label>
            <div class="input-wrapper">
              <svg class="input-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path></svg>
              <input type="text" id="username" name="username" required 
                placeholder="Masukkan username" autocomplete="username">
            </div>
          </div>
          
          <div class="form-group">
            <label for="password">Password</label>
            <div class="input-wrapper">
              <svg class="input-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
              <input type="password" id="password" name="password" required 
                placeholder="Masukkan password" autocomplete="current-password">
              <div class="toggle-password" id="toggle-password">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                  <path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path>
                  <path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path>
                </svg>
              </div>
            </div>
          </div>

          <div class="login-error" id="login-error" style="display: none;">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
            <span id="error-text"></span>
          </div>

          <button type="submit" class="btn-login" id="btn-login">
            <span class="btn-text">Masuk Sekarang</span>
          </button>
        </form>
      </div>
    </div>
  `;
}

export function initLogin() {
  const form = document.getElementById('login-form');
  const errorEl = document.getElementById('login-error');
  const errorText = document.getElementById('error-text');
  const btnLogin = document.getElementById('btn-login');
  const passwordInput = document.getElementById('password');
  const togglePassword = document.getElementById('toggle-password');

  // Tampilkan alasan logout jika ada (misal sesi dicabut, token kedaluwarsa)
  const logoutReason = sessionStorage.getItem('pos_logout_reason');
  if (logoutReason) {
    sessionStorage.removeItem('pos_logout_reason');
    errorText.textContent = logoutReason;
    errorEl.style.display = 'flex';
  }

  // Focus username input with animation delay
  setTimeout(() => {
    document.getElementById('username')?.focus();
  }, 300);

  // Toggle Password
  togglePassword?.addEventListener('click', () => {
    const type = passwordInput.getAttribute('type') === 'password' ? 'text' : 'password';
    passwordInput.setAttribute('type', type);

    // Update icon
    const icon = type === 'password'
      ? '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path>'
      : '<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21"></path>';

    togglePassword.querySelector('svg').innerHTML = icon;
  });

  form?.addEventListener('submit', async (e) => {
    e.preventDefault();

    const username = document.getElementById('username').value.trim();
    const password = document.getElementById('password').value;

    if (!username || !password) {
      showError('Username dan password wajib diisi');
      return;
    }

    // Disable button & Show loading
    btnLogin.disabled = true;
    btnLogin.innerHTML = '<div class="login-spinner"></div> Memproses...';
    errorEl.style.display = 'none';

    try {
      // Small artificial delay for better UX (so user sees loading state)
      const start = Date.now();
      const result = await loginUser(username, password);
      const elapsed = Date.now() - start;

      if (elapsed < 500) await new Promise(r => setTimeout(r, 500 - elapsed));

      if (result.success) {
        saveSession({
          userId: result.user.id,
          username: result.user.username,
          fullName: result.user.full_name || result.user.name,
          role: result.user.role,
          token: result.token
        });

        // Redirect to dashboard
        window.location.hash = '/';
        window.location.reload();
      } else {
        showError(result.message || 'Login gagal, periksa username/password');
      }
    } catch (err) {
      console.error('Login error:', err);
      showError(err.message || 'Gagal terhubung ke server');
    } finally {
      if (!errorEl.style.display || errorEl.style.display === 'none') {
        // Success case - button stays loading until reload
      } else {
        // Error case - reset button
        btnLogin.disabled = false;
        btnLogin.innerHTML = '<span class="btn-text">Masuk Sekarang</span>';
      }
    }
  });

  function showError(message) {
    errorText.textContent = message;
    errorEl.style.display = 'flex';
    btnLogin.disabled = false;
    btnLogin.innerHTML = '<span class="btn-text">Masuk Sekarang</span>';

    // Shake animation reset
    errorEl.style.animation = 'none';
    errorEl.offsetHeight; // trigger reflow
    errorEl.style.animation = 'shake 0.4s ease-in-out';
  }
}
