// API Service - POS Admin Mobile
// Set to false to use real backend, true for mock data
const USE_DUMMY = false;

// ═══════════════════════════════════════════════════════════
// IMPORTS
// ═══════════════════════════════════════════════════════════
import { getCache, setCache, clearExpiredCache, isIDBSupported } from '../utils/idb.js';

// Feature flag: Use Rust microservice for optimized endpoints
const USE_RUST_SERVICE = true; // Set to false to use Express only

// Dynamic API server configuration
let apiProtocol = 'http';
let apiHost = window.location.hostname === 'localhost'
  ? 'localhost'
  : window.location.hostname;
let apiPort = 3001;
let rustPort = 3002; // Rust service port

// Get current API base URL (Express)
function getApiBase() {
  const portStr = (apiPort && apiPort !== 80 && apiPort !== 443) ? `:${apiPort}` : '';
  return `${apiProtocol}://${apiHost}${portStr}/api`;
}

// Get Rust service API base URL
function getRustApiBase() {
  // If running on local dev (localhost), we can use the direct port 3002
  // If running on a tunnel or public IP, we MUST use the proxy through the main port (3001)
  // to avoid CORS issues and tunnel limitations.
  if (apiHost === 'localhost') {
    const portStr = (rustPort && rustPort !== 80 && rustPort !== 443) ? `:${rustPort}` : '';
    return `${apiProtocol}://${apiHost}${portStr}/api/v2`;
  }

  // Untuk non-localhost, gunakan Express endpoint yang sama (/api/v2 di-mount di router
  // yang sama dengan /api di api-server.js). Rust service hanya diakses langsung di localhost:3002.
  return getApiBase() + '/v2';
}

// ═══════════════════════════════════════════════════════════
// RUST SERVICE HELPER - Fetch dengan race timeout
// ═══════════════════════════════════════════════════════════

/**
 * Fetch dengan race antara Rust dan Express service.
 * Rust diberi timeout pendek (500ms), kalau gagal langsung fallback ke Express.
 * Ini menghindari delay saat Rust service tidak berjalan.
 */
async function fetchWithRace(rustUrl, expressUrl, options = {}) {
  const RUST_TIMEOUT = 500; // 500ms timeout untuk Rust
  
  const rustPromise = apiFetch(rustUrl, options)
    .then(data => ({ success: true, source: 'rust', data }))
    .catch(err => ({ success: false, source: 'rust', error: err }));
  
  const timeoutPromise = new Promise(resolve => 
    setTimeout(() => resolve({ success: false, source: 'timeout' }), RUST_TIMEOUT)
  );
  
  // Race antara Rust dan timeout
  const rustResult = await Promise.race([rustPromise, timeoutPromise]);
  
  if (rustResult.success && rustResult.source === 'rust') {
    return rustResult.data;
  }
  
  // Fallback ke Express
  return apiFetch(expressUrl, options);
}

// ═══════════════════════════════════════════════════════════
// DATA CACHING LAYER
// ═══════════════════════════════════════════════════════════
const dataCache = new Map();
const CACHE_MAX_SIZE = 50; // Batas entri agar tidak membengkak di memori

// TTL per pola URL. Sedikit lebih panjang dari backend agar tidak sering miss.
function getCacheTTL(url) {
  if (url.includes('/settings')) return 5 * 60 * 1000; // 5 menit — jarang berubah
  if (url.includes('/categories')) return 5 * 60 * 1000; // 5 menit — jarang berubah
  if (url.includes('/products')) return 60 * 1000;      // 60s — stok bisa berubah
  if (url.includes('/dashboard')) return 35 * 1000;      // 35s — sedikit > backend 30s
  return 30 * 1000;                                        // 30s default
}

export function clearCache(keyPrefix = null) {
  if (!keyPrefix) {
    dataCache.clear();
    console.log('[API Cache] All cleared');
  } else {
    for (const key of dataCache.keys()) {
      if (key.includes(keyPrefix)) dataCache.delete(key);
    }
    console.log(`[API Cache] Cleared keys containing: ${keyPrefix}`);
  }
}

// Set API server (called from discovery)
export function setApiServer(host, port = 3001, protocol = 'http') {
  console.log('[API] Check for Proxy v3.2-fix');
  apiHost = host;
  apiPort = port;
  apiProtocol = protocol;
  console.log(`[API] Server set to ${protocol}://${host}:${port}`);
}

// Get current server info
export function getApiServer() {
  return { host: apiHost, port: apiPort };
}

// Persistent device identifier — survives logout
function getDeviceId() {
  let id = localStorage.getItem('pos_device_id');
  if (!id) {
    id = crypto.randomUUID();
    localStorage.setItem('pos_device_id', id);
  }
  return id;
}

// Baca token dari localStorage tanpa import session.js (hindari circular dep)
function getAuthToken() {
  try {
    const session = localStorage.getItem('pos_admin_session');
    return session ? JSON.parse(session).token : null;
  } catch {
    return null;
  }
}

// Handle 401: hapus sesi dan redirect ke login
// message: pesan dari server (misal "Sesi perangkat telah dicabut")
function handleUnauthorized(message = null) {
  localStorage.removeItem('pos_admin_session');
  localStorage.removeItem('pos_admin_last_activity');
  dataCache.clear();
  // Simpan pesan flash agar login page bisa tampilkan alasan
  if (message) sessionStorage.setItem('pos_logout_reason', message);
  // Jika sudah di halaman login, jangan reload (hindari infinite loop)
  const currentHash = window.location.hash.replace('#', '').split('?')[0] || '/';
  if (currentHash === '/login') return;
  window.location.hash = '/login';
  window.location.reload();
}

async function fetchWithRetry(url, options, maxRetries = 2, delay = 1500) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fetch(url, options);
    } catch (err) {
      // Hanya retry jika error network (bukan 4xx/5xx),
      // dan masih ada attempt tersisa
      const isNetworkError = !err.status; // TypeError: Failed to fetch
      if (!isNetworkError || attempt === maxRetries) throw err;
      await new Promise(r => setTimeout(r, delay * (attempt + 1)));
    }
  }
}

// Helper: fetch with error handling and cache (Memory + IndexedDB)
async function apiFetch(url, options = {}) {
  const isGet = !options.method || options.method === 'GET';
  const cacheKey = url;

  // 1. Check memory cache first (fastest)
  if (isGet && !options.bypassCache && dataCache.has(cacheKey)) {
    const entry = dataCache.get(cacheKey);
    if (Date.now() < entry.expiry) {
      return entry.data;
    }
    dataCache.delete(cacheKey);
  }

  // 2. Check IndexedDB cache (persistent, survives page reload)
  if (isGet && !options.bypassCache && isIDBSupported()) {
    const idbCache = await getCache(cacheKey);
    if (idbCache) {
      // Return cache meski expired (untuk offline mode)
      // Tandai dengan flag _fromCache dan _isExpired
      const result = {
        ...idbCache.data,
        _fromCache: true,
        _isExpired: idbCache.isExpired,
        _cacheAge: idbCache.age
      };
      
      // Jika cache masih fresh, return langsung
      if (!idbCache.isExpired) {
        // Also store to memory cache untuk speed
        dataCache.set(cacheKey, { 
          data: idbCache.data, 
          expiry: Date.now() + getCacheTTL(url) 
        });
      }
      
      // Tetap lanjut ke network untuk refresh (background)
      // Tapi return cache dulu untuk UX cepat
      if (!options.skipBackgroundRefresh) {
        return result;
      }
    }
  }

  // Sertakan token JWT di header Authorization (jika ada)
  const token = getAuthToken();
  const authHeaders = token ? { 'Authorization': `Bearer ${token}` } : {};

  try {
    const res = await fetchWithRetry(url, {
      ...options,
      headers: { 'Content-Type': 'application/json', ...authHeaders, ...options.headers }
    });

    // Token kedaluwarsa / tidak valid / sesi dicabut — logout otomatis
    if (res.status === 401 && !options.skipAuthRedirect) {
      try {
        const errData = await res.clone().json();
        handleUnauthorized(errData.message);
      } catch {
        handleUnauthorized();
      }
      return;
    }

    let data;
    try {
      data = await res.json();
    } catch (parseError) {
      throw new Error(`Server error (${res.status})`);
    }

    if (!res.ok || data.success === false) {
      throw new Error(data.message || `Request failed (${res.status})`);
    }

    // Cache successful GET results (Memory + IndexedDB)
    if (isGet) {
      // Memory cache (fast)
      if (dataCache.size >= CACHE_MAX_SIZE) {
        dataCache.delete(dataCache.keys().next().value);
      }
      dataCache.set(cacheKey, { data, expiry: Date.now() + getCacheTTL(url) });
      
      // IndexedDB cache (persistent)
      if (isIDBSupported()) {
        await setCache(cacheKey, data, getCacheTTL(url) * 2); // IDB cache lebih lama
      }
    } else {
      // Clear relevant cache on mutations
      if (url.includes('/products')) clearCache('/products');
      if (url.includes('/categories')) clearCache('/categories');
      if (url.includes('/transactions')) clearCache('/transactions');
      if (url.includes('/debts')) clearCache('/debts');
      if (url.includes('/dashboard')) clearCache('/dashboard');
      if (url.includes('/users') || url.includes('/auth')) clearCache('/users');
    }

    return data;
  } catch (err) {
    // 3. Network error — coba IndexedDB cache sebagai fallback
    if (isGet && isIDBSupported()) {
      const idbCache = await getCache(cacheKey);
      if (idbCache) {
        return {
          ...idbCache.data,
          _fromCache: true,
          _isExpired: true,
          _cacheAge: idbCache.age,
          _offline: true
        };
      }
    }
    
    // More specific network error message
    if (err.name === 'TypeError' && err.message.includes('fetch')) {
      throw new Error('Tidak dapat terhubung ke server. Periksa koneksi jaringan.');
    }
    throw err;
  }
}

