// Dashboard Stats
export async function fetchStats() {
  if (USE_DUMMY) return dummyData.stats;

  // Use race between Rust (with timeout) and Express to avoid delay
  let data;
  if (USE_RUST_SERVICE) {
    try {
      data = await fetchWithRace(
        `${getRustApiBase()}/dashboard/stats`,
        `${getApiBase()}/dashboard/stats`,
        { bypassCache: true }
      );
      
      // If Rust returned data (has Rust-specific fields), supplement missing fields from Express
      if (data && !data.total_products) {
        try {
          const expressData = await apiFetch(`${getApiBase()}/dashboard/stats`, { bypassCache: true });
          data.total_products = expressData.total_products;
          data.yesterday_profit = expressData.yesterday_profit;
          data.debt_total_outstanding = expressData.debt_total_outstanding;
          data.low_stock_products = expressData.low_stock_products;
          data.slowMovingProducts = expressData.slowMovingProducts;
        } catch (_) { /* Express supplement is best-effort */ }
      }
    } catch (err) {
      data = await apiFetch(`${getApiBase()}/dashboard/stats`, { bypassCache: true });
    }
  } else {
    data = await apiFetch(`${getApiBase()}/dashboard/stats`, { bypassCache: true });
  }

  // Transform last_7_days to weekSales format {day, amount}
  // Robustly handle missing days by generating the last 7 dates
  const dayNames = ['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'];
  const weekSales = [];

  // Generate last 7 days (including today)
  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().split('T')[0]; // YYYY-MM-DD

    // Find matching data from API (backend returns date(created_at) which is YYYY-MM-DD)
    const found = (data.last_7_days || []).find(item => item.date === dateStr);

    weekSales.push({
      day: dayNames[d.getDay()],
      amount: found ? (found.total || found.sales || 0) : 0,
      fullDate: dateStr
    });
  }

  // Generate last 30 days
  const monthSales = [];
  for (let i = 29; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().split('T')[0];

    const found = (data.last_30_days || []).find(item => item.date === dateStr);

    // Format DD/MM for 30 days chart
    const Month = d.getMonth() + 1;
    const Day = d.getDate();
    const label = `${Day < 10 ? '0' + Day : Day}/${Month < 10 ? '0' + Month : Month}`;

    monthSales.push({
      day: label,
      amount: found ? (found.total || found.sales || 0) : 0,
      fullDate: dateStr
    });
  }

  // Transform top_products_today to topProducts format {name, sold, revenue}
  // Handle both Express (product_name, qty) and Rust (name, quantity) field names
  const topProducts = (data.top_products_today || []).map(p => ({
    name: p.product_name || p.name,
    sold: p.qty || p.quantity,
    revenue: p.total
  }));

  // Build alerts from low stock and overdue
  const recentAlerts = [];
  if (data.low_stock_products) {
    data.low_stock_products.forEach(p => {
      // Use configured threshold (server now uses 10)
      recentAlerts.push({
        type: 'lowStock',
        message: `${p.name} stok tersisa ${p.stock}`,
        time: 'Stok rendah'
      });
    });
  }
  if (data.debt_overdue_count > 0) {
    recentAlerts.push({
      type: 'overdue',
      message: `${data.debt_overdue_count} piutang jatuh tempo`,
      time: 'Perlu tindakan'
    });
  }

  // Handle both Express (flat fields) and Rust (nested objects) response formats
  const todaySales = data.today_sales_total || data.today_sales?.total || 0;
  const todayCount = data.today_sales_count || data.today_sales?.count || 0;
  const yesterdaySales = data.yesterday_sales_total || data.yesterday_sales?.total || 0;
  const yesterdayCount = data.yesterday_sales_count || data.yesterday_sales?.count || 0;
  const todayProfit = data.today_profit?.profit ?? data.today_profit ?? 0;
  const yesterdayProfit = data.yesterday_profit?.profit ?? data.yesterday_profit ?? 0;

  return {
    todaySales,
    yesterdaySales,
    todayProfit,
    yesterdayProfit,
    todayTransactions: todayCount,
    yesterdayTransactions: yesterdayCount,
    totalProducts: data.total_products || 0,
    lowStockCount: data.low_stock_count || 0,
    totalDebt: data.debt_total_outstanding || data.totalDebt || 0,
    overdueCount: data.debt_overdue_count || data.overdueCount || 0,
    weekSales,
    monthSales,
    topProducts,
    slowMovingProducts: data.slowMovingProducts || [],
    recentAlerts,
    fetchedAt: new Date().toISOString()
  };
}

// Slow Moving Products
export async function fetchSlowMovingProducts(inactiveDays = 120) {
  if (USE_DUMMY) {
    return dummyData.stats.slowMovingProducts.filter(p => p.daysSinceLastSale >= inactiveDays);
  }

  // Try Rust service first if enabled
  let data;
  if (USE_RUST_SERVICE) {
    try {
      data = await apiFetch(`${getRustApiBase()}/products/slow-moving?days=${inactiveDays}`);
      console.log('[Rust Service] Slow moving products fetched successfully');
      // Rust returns array directly, Express returns {products: [...]}
      const products = Array.isArray(data) ? data : (data.products || []);
      return products.map(p => ({
        name: p.name,
        stock: p.stock,
        lastSold: p.last_sale || p.last_sold_date,
        daysSinceLastSale: p.days_since_sale || p.days_since_last_sale || p.days_inactive || inactiveDays,
        daysSinceAdded: p.days_since_added
      }));
    } catch (err) {
      console.warn('[Rust Service] Unavailable, falling back to Express:', err.message);
      data = await apiFetch(`${getApiBase()}/products/slow-moving?days=${inactiveDays}`);
    }
  } else {
    data = await apiFetch(`${getApiBase()}/products/slow-moving?days=${inactiveDays}`);
  }

  return (data.products || []).map(p => ({
    name: p.name,
    stock: p.stock,
    lastSold: p.last_sold_date,
    daysSinceLastSale: p.days_since_last_sale || p.days_inactive || inactiveDays,
    daysSinceAdded: p.days_since_added
  }));
}

// Current User
export async function fetchCurrentUser() {
  if (USE_DUMMY) return dummyData.currentUser;

  // Get userId from session
  const session = JSON.parse(localStorage.getItem('pos_admin_session') || 'null');
  const userId = session?.userId || 1;

  try {
    const data = await apiFetch(`${getApiBase()}/users/${userId}`);
    const user = data.user || {};
    return {
      id: user.id,
      username: user.username || 'User',
      fullName: user.full_name || user.username || 'User',
      role: user.role || 'cashier',
      lastLogin: user.last_login || null
    };
  } catch (err) {
    console.error('[API] fetchCurrentUser failed:', err.message);
    // If user is not found, the session is stale. Clear it and go to login.
    if (err.message.includes('tidak ditemukan') || err.message.includes('404')) {
      console.warn('[Session] User ID no longer valid, logging out...');
      handleUnauthorized('Sesi pengguna tidak valid');
    }
    throw err;
  }
}

// Login
export async function loginUser(username, password) {
  if (USE_DUMMY) {
    return { success: true, user: dummyData.currentUser, token: 'dummy-token' };
  }
  const data = await apiFetch(`${getApiBase()}/auth/login`, {
    method: 'POST',
    skipAuthRedirect: true, // 401 dari login = kredensial salah, bukan sesi expired
    body: JSON.stringify({
      username,
      password,
      device_id: getDeviceId(),
      device_name: navigator.userAgent.slice(0, 150)
    })
  });
  return data;
}

