// Generate Barcode
export async function generateBarcode() {
  if (USE_DUMMY) {
    const now = new Date();
    const prefix = '2' + now.getFullYear().toString().slice(2) +
      (now.getMonth() + 1).toString().padStart(2, '0');
    return prefix + Math.floor(Math.random() * 1000000).toString().padStart(6, '0');
  }
  const data = await apiFetch(`${getApiBase()}/products/generate-barcode`, { bypassCache: true });
  return data.barcode;
}

// Products
const LOW_STOCK_THRESHOLD = 15;

export async function fetchProducts(search = '', filter = {}, limit = null, offset = 0) {
  if (USE_DUMMY) {
    let products = [...dummyData.products];
    if (search) products = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
    if (filter.lowStock) products = products.filter(p => p.stock < LOW_STOCK_THRESHOLD);
    return products;
  }

  const params = new URLSearchParams();
  if (search) params.append('search', search);
  if (filter.categoryId) params.append('category_id', filter.categoryId);
  if (filter.lowStock) params.append('low_stock', 'true');
  if (filter.sortBy) params.append('sort_by', filter.sortBy);
  if (filter.sortOrder) params.append('sort_order', filter.sortOrder);
  if (limit) params.append('limit', limit);
  if (offset) params.append('offset', offset);

  const data = await apiFetch(`${getApiBase()}/products?${params}`);

  // Backend can return {data: [...], total: ...} OR {0: {...}, 1: {...}} 
  let productsArr = data.data || data.products;
  let total = data.total;

  if (!productsArr) {
    // Convert object with numeric keys to array (fallback for old API format)
    productsArr = Object.keys(data)
      .filter(k => k !== 'success' && !isNaN(k))
      .map(k => data[k]);
    if (!total) total = productsArr.length;
  }

  let result = productsArr.map(p => ({
    id: p.id, name: p.name, barcode: p.barcode,
    price: p.price, cost: p.cost, stock: p.stock,
    unit: p.unit || 'pcs',
    category: p.category_name || p.category, categoryId: p.category_id
  }));

  if (limit !== null) {
    return { data: result, total: total || result.length };
  }

  return result;
}

export async function fetchProductById(id) {
  if (USE_DUMMY) return dummyData.products.find(p => p.id === id);
  const data = await apiFetch(`${getApiBase()}/products/${id}`);
  return data.product;
}

export async function createProduct(productData) {
  if (USE_DUMMY) return { success: true, id: Date.now() };

  const session = JSON.parse(localStorage.getItem('pos_admin_session') || 'null');
  const payload = {
    ...productData,
    userId: session?.userId || 1,
    userName: session?.username || 'Admin'
  };

  return await apiFetch(`${getApiBase()}/products`, {
    method: 'POST', body: JSON.stringify(payload)
  });
}

export async function updateProduct(id, productData) {
  if (USE_DUMMY) return { success: true };

  const session = JSON.parse(localStorage.getItem('pos_admin_session') || 'null');
  const payload = {
    ...productData,
    userId: session?.userId || 1,
    userName: session?.username || 'Admin'
  };

  return await apiFetch(`${getApiBase()}/products/${id}`, {
    method: 'PUT', body: JSON.stringify(payload)
  });
}

export async function deleteProduct(id) {
  if (USE_DUMMY) return { success: true };
  return await apiFetch(`${getApiBase()}/products/${id}`, { method: 'DELETE' });
}

// Stock History
export async function fetchStockHistory(productId = null) {
  if (USE_DUMMY) return [];
  const url = productId
    ? `${getApiBase()}/stock-history?productId=${productId}`
    : `${getApiBase()}/stock-history`;
  const data = await apiFetch(url);
  return (data.history || []).map(h => ({
    id: h.id,
    productId: h.product_id,
    productName: h.product_name,
    changeType: h.event_type || 'manual',
    quantity: h.quantity_change || 0,
    previousStock: h.quantity_before,
    newStock: h.quantity_after,
    notes: h.notes,
    createdAt: h.created_at,
    userName: h.user_name
  }));
}

// Quick stock update
export async function updateStock(productId, adjustment, notes = '') {
  // Get userId from session
  const session = JSON.parse(localStorage.getItem('pos_admin_session') || 'null');
  const userId = session?.userId || 1;

  const data = await apiFetch(`${getApiBase()}/products/${productId}/stock`, {
    method: 'POST',
    body: JSON.stringify({ adjustment, userId, notes })
  });
  return data;
}

// Transactions
export async function fetchTransactions(filter = {}) {
  if (USE_DUMMY) return dummyData.transactions;

  const params = new URLSearchParams();
  if (filter.status && filter.status !== 'all') params.append('status', filter.status);
  if (filter.dateFrom) params.append('date_from', filter.dateFrom);
  if (filter.dateTo) params.append('date_to', filter.dateTo);
  if (filter.search) params.append('search', filter.search);

  const data = await apiFetch(`${getApiBase()}/transactions?${params}`);


  return (data.transactions || []).map(tx => ({
    id: tx.id,
    invoiceNumber: tx.invoice_number,
    date: tx.created_at,
    total: tx.total,
    amountPaid: tx.amount_paid,
    remainingBalance: tx.remaining_balance,
    change: tx.change_amount,
    items: tx.item_count || tx.items?.length || 0,
    status: tx.payment_status || 'lunas',
    paymentStatus: tx.payment_status,
    paymentMethod: tx.payment_method,
    cashierName: tx.cashier_name,
    customerName: tx.customer_name,
    customerPhone: tx.customer_phone,
    dueDate: tx.due_date,
    paymentNotes: tx.payment_notes,
    itemDetails: tx.items
  }));
}

export async function fetchTransactionById(id) {
  if (USE_DUMMY) return dummyData.transactions.find(tx => tx.id === id);

  // Try Rust service first if enabled
  let data;
  let tx;
  if (USE_RUST_SERVICE) {
    try {
      data = await apiFetch(`${getRustApiBase()}/transactions/${id}`);
      console.log('[Rust Service] Transaction detail fetched successfully');
      // Rust returns transaction directly, Express returns {transaction: {...}}
      tx = data.transaction || data;
    } catch (err) {
      console.warn('[Rust Service] Unavailable, falling back to Express:', err.message);
      data = await apiFetch(`${getApiBase()}/transactions/${id}`);
      tx = data.transaction;
    }
  } else {
    data = await apiFetch(`${getApiBase()}/transactions/${id}`);
    tx = data.transaction;
  }

  return {
    id: tx.id,
    invoiceNumber: tx.invoice_number || tx.invoiceNumber,
    date: tx.created_at || tx.date,
    total: tx.total,
    amountPaid: tx.amount_paid || tx.amountPaid,
    remainingBalance: tx.remaining_balance || tx.remainingBalance,
    change: tx.change_amount || tx.change,
    items: tx.item_count || tx.items?.length || 0,
    status: tx.payment_status || tx.status || 'lunas',
    paymentMethod: tx.payment_method || tx.paymentMethod,
    cashierName: tx.cashier_name || tx.cashierName,
    customerName: tx.customer_name || tx.customerName,
    dueDate: tx.due_date || tx.dueDate,
    itemDetails: tx.items || tx.itemDetails,
    paymentHistory: tx.payment_history || tx.paymentHistory || [],
    paymentNotes: tx.payment_notes || tx.paymentNotes
  };
}

export async function voidTransaction(id, reason) {
  if (USE_DUMMY) return { success: true };
  return await apiFetch(`${getApiBase()}/transactions/${id}/void`, {
    method: 'POST', body: JSON.stringify({ reason })
  });
}

// Debts
export async function fetchDebts(filter = {}) {
  if (USE_DUMMY) return dummyData.debts;

  const params = new URLSearchParams();
  if (filter.status && filter.status !== 'all') params.append('status', filter.status);
  if (filter.overdue) params.append('overdue', 'true');
  if (filter.search) params.append('search', filter.search);

  const data = await apiFetch(`${getApiBase()}/debts?${params}`);
  return (data.debts || []).map(d => ({
    id: d.invoice_number || d.id,
    customerName: d.customer_name,
    customerPhone: d.customer_phone,
    date: d.created_at,
    total: d.total,
    totalPaid: d.total_paid,
    remainingBalance: d.remaining_balance,
    dueDate: d.due_date,
    status: d.payment_status,
    isOverdue: d.is_overdue,
    daysOverdue: d.days_overdue || 0
  }));
}

export async function fetchDebtSummary() {
  if (USE_DUMMY) return dummyData.debtSummary;
  const data = await apiFetch(`${getApiBase()}/debts/summary`);

  // Transform by_status array to object with defaults
  const byStatusDefault = {
    pending: { count: 0, total: 0 },
    hutang: { count: 0, total: 0 },
    cicilan: { count: 0, total: 0 }
  };

  // If by_status is an array, transform it to object
  if (Array.isArray(data.by_status)) {
    data.by_status.forEach(item => {
      if (item.payment_status && byStatusDefault[item.payment_status]) {
        byStatusDefault[item.payment_status] = {
          count: item.count || 0,
          total: item.total || 0
        };
      }
    });
  }

  return {
    totalOutstanding: data.total_outstanding || 0,
    totalCustomers: data.total_count || 0,
    overdueCount: data.overdue_count || 0,
    overdueAmount: data.overdue_total || 0,
    byStatus: byStatusDefault
  };
}

export async function addPayment(transactionId, amount, method, notes) {
  if (USE_DUMMY) return { success: true };
  const session = JSON.parse(localStorage.getItem('pos_admin_session') || 'null');
  return await apiFetch(`${getApiBase()}/transactions/${transactionId}/payment`, {
    method: 'POST',
    body: JSON.stringify({ amount, method, userId: session?.userId || 1, notes })
  });
}

export async function fetchPaymentHistory(transactionId) {
  if (USE_DUMMY) return [];
  const data = await apiFetch(`${getApiBase()}/transactions/${transactionId}/payments`);
  return (data.payments || []).map(p => ({
    id: p.id, amount: p.amount, method: p.payment_method,
    date: p.payment_date, receivedBy: p.received_by_name, notes: p.notes
  }));
}

// Settings
export async function fetchSettings() {
  if (USE_DUMMY) return { default_margin_percent: 10.5 };
  try {
    const data = await apiFetch(`${getApiBase()}/settings`);
    return data.settings || {};
  } catch (e) {
    console.warn('Failed to fetch settings, using defaults', e);
    return { default_margin_percent: 10.5 };
  }
}


export async function updateSettings(settings) {
  if (USE_DUMMY) return { success: true };
  try {
    const data = await apiFetch(`${getApiBase()}/settings`, {
      method: 'POST',
      body: JSON.stringify(settings)
    });
    return data;
  } catch (e) {
    console.error('Failed to update settings', e);
    throw e;
  }
}

export async function fetchUsers() {
  // Bypass cache for activity tracking to ensure fresh data
  const data = await apiFetch(`${getApiBase()}/users`, { bypassCache: true });
  return data.users;
}
