// IndexedDB Helper untuk Offline Cache
// Menyimpan data API ke local storage untuk akses offline

const DB_NAME = 'pos_admin_cache';
const DB_VERSION = 1;
const STORE_NAME = 'api_cache';

let db = null;

/**
 * Inisialisasi IndexedDB
 */
export async function initDB() {
  if (db) return db;
  
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    
    request.onerror = () => reject(request.error);
    request.onsuccess = () => {
      db = request.result;
      resolve(db);
    };
    
    request.onupgradeneeded = (event) => {
      const database = event.target.result;
      if (!database.objectStoreNames.contains(STORE_NAME)) {
        const store = database.createObjectStore(STORE_NAME, { keyPath: 'key' });
        store.createIndex('timestamp', 'timestamp', { unique: false });
      }
    };
  });
}

/**
 * Simpan data ke cache
 * @param {string} key - URL endpoint atau key unik
 * @param {*} data - Data yang akan disimpan
 * @param {number} ttlMs - Time to live dalam ms (default: 5 menit)
 */
export async function setCache(key, data, ttlMs = 5 * 60 * 1000) {
  try {
    const database = await initDB();
    const transaction = database.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    
    const entry = {
      key,
      data,
      timestamp: Date.now(),
      expiry: Date.now() + ttlMs
    };
    
    await new Promise((resolve, reject) => {
      const request = store.put(entry);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
    
    return true;
  } catch (err) {
    console.warn('[IDB] Failed to set cache:', err);
    return false;
  }
}

/**
 * Ambil data dari cache
 * @param {string} key - URL endpoint atau key unik
 * @returns {object|null} - { data, isExpired, fetchedAt } atau null
 */
export async function getCache(key) {
  try {
    const database = await initDB();
    const transaction = database.transaction([STORE_NAME], 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    
    const entry = await new Promise((resolve, reject) => {
      const request = store.get(key);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
    
    if (!entry) return null;
    
    const isExpired = Date.now() > entry.expiry;
    
    return {
      data: entry.data,
      isExpired,
      fetchedAt: entry.timestamp,
      age: Date.now() - entry.timestamp
    };
  } catch (err) {
    console.warn('[IDB] Failed to get cache:', err);
    return null;
  }
}

/**
 * Hapus data dari cache
 */
export async function deleteCache(key) {
  try {
    const database = await initDB();
    const transaction = database.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    
    await new Promise((resolve, reject) => {
      const request = store.delete(key);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
    
    return true;
  } catch (err) {
    console.warn('[IDB] Failed to delete cache:', err);
    return false;
  }
}

/**
 * Bersihkan cache yang expired
 */
export async function clearExpiredCache() {
  try {
    const database = await initDB();
    const transaction = database.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const index = store.index('timestamp');
    
    const now = Date.now();
    let deletedCount = 0;
    
    await new Promise((resolve, reject) => {
      const request = index.openCursor();
      
      request.onsuccess = (event) => {
        const cursor = event.target.result;
        if (cursor) {
          if (cursor.value.expiry < now) {
            cursor.delete();
            deletedCount++;
          }
          cursor.continue();
        } else {
          resolve(deletedCount);
        }
      };
      
      request.onerror = () => reject(request.error);
    });
    
    return deletedCount;
  } catch (err) {
    console.warn('[IDB] Failed to clear expired:', err);
    return 0;
  }
}

/**
 * Check apakah browser support IndexedDB
 */
export function isIDBSupported() {
  return 'indexedDB' in window;
}

/**
 * Get cache info untuk debugging
 */
export async function getCacheInfo() {
  try {
    const database = await initDB();
    const transaction = database.transaction([STORE_NAME], 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    
    const count = await new Promise((resolve, reject) => {
      const request = store.count();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
    
    return { count, supported: true };
  } catch (err) {
    return { count: 0, supported: false, error: err.message };
  }
}
