// Session Management Utility
// Handles auto-logout after inactivity

import { clearCache } from '../services/api.js';

const INACTIVITY_TIMEOUT = 10 * 60 * 1000; // 10 minutes in ms
const MAX_SESSION_AGE = 24 * 60 * 60 * 1000; // 24 hours absolute max
const SESSION_KEY = 'pos_admin_session';
const LAST_ACTIVITY_KEY = 'pos_admin_last_activity';

let inactivityTimer = null;
let isInitialized = false;
let _lastActivityTime = 0;
const ACTIVITY_THROTTLE = 5000; // tulis localStorage & reset timer max 1x per 5 detik

/**
 * Activity events to track
 */
const ACTIVITY_EVENTS = [
  'mousedown',
  'mousemove',
  'keydown',
  'scroll',
  'touchstart',
  'touchmove',
  'click'
];

/**
 * Initialize session management
 */
export function initSession() {
  if (isInitialized) return;

  // Check if already logged in
  if (!isLoggedIn()) {
    redirectToLogin();
    return;
  }

  // Setup activity listeners
  ACTIVITY_EVENTS.forEach(event => {
    document.addEventListener(event, handleActivity, { passive: true });
  });

  // Start inactivity timer
  resetInactivityTimer();

  // Check for expired session on visibility change
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible') {
      checkSessionValidity();
    }
  });

  isInitialized = true;
  console.log('[Session] Initialized with 10 minute timeout');
}

/**
 * Handle user activity — throttled agar tidak dipanggil ratusan kali/detik
 * saat scroll/mousemove (localStorage I/O + clearTimeout/setTimeout churn).
 */
function handleActivity() {
  const now = Date.now();
  if (now - _lastActivityTime < ACTIVITY_THROTTLE) return;
  _lastActivityTime = now;
  updateLastActivity();
  resetInactivityTimer();
}

/**
 * Update last activity timestamp
 */
function updateLastActivity() {
  localStorage.setItem(LAST_ACTIVITY_KEY, Date.now().toString());
}

/**
 * Get last activity timestamp
 */
function getLastActivity() {
  const timestamp = localStorage.getItem(LAST_ACTIVITY_KEY);
  return timestamp ? parseInt(timestamp) : Date.now();
}

/**
 * Reset the inactivity timer
 */
function resetInactivityTimer() {
  if (inactivityTimer) {
    clearTimeout(inactivityTimer);
  }

  inactivityTimer = setTimeout(() => {
    console.log('[Session] Inactivity timeout reached');
    logout('Sesi berakhir karena tidak ada aktivitas');
  }, INACTIVITY_TIMEOUT);
}

/**
 * Check if session is still valid
 */
function checkSessionValidity() {
  const lastActivity = getLastActivity();
  const elapsed = Date.now() - lastActivity;

  if (elapsed >= INACTIVITY_TIMEOUT) {
    console.log('[Session] Session expired while away');
    logout('Sesi berakhir karena tidak ada aktivitas');
  } else {
    // Reset timer with remaining time
    const remaining = INACTIVITY_TIMEOUT - elapsed;
    if (inactivityTimer) clearTimeout(inactivityTimer);
    inactivityTimer = setTimeout(() => {
      logout('Sesi berakhir karena tidak ada aktivitas');
    }, remaining);
  }
}

/**
 * Clear expired session data from localStorage
 */
function clearExpiredSession() {
  localStorage.removeItem(SESSION_KEY);
  localStorage.removeItem(LAST_ACTIVITY_KEY);
}

/**
 * Check if user is logged in (with expiry validation)
 */
export function isLoggedIn() {
  const session = localStorage.getItem(SESSION_KEY);
  if (!session) return false;

  try {
    const parsed = JSON.parse(session);

    // 1. Check absolute session age (max 24 hours from login)
    if (parsed.loginAt) {
      const sessionAge = Date.now() - new Date(parsed.loginAt).getTime();
      if (sessionAge >= MAX_SESSION_AGE) {
        clearExpiredSession();
        return false;
      }
    }

    // 2. Token harus ada dan tidak kosong
    if (!parsed.token) {
      clearExpiredSession();
      return false;
    }

    // 3. Check inactivity across browser close (LAST_ACTIVITY_KEY persists in localStorage)
    //    This catches the case where browser/PWA was closed while user was inactive
    const lastActivity = localStorage.getItem(LAST_ACTIVITY_KEY);
    if (lastActivity) {
      const elapsed = Date.now() - parseInt(lastActivity);
      if (elapsed >= INACTIVITY_TIMEOUT) {
        clearExpiredSession();
        return false;
      }
    }

    return true;
  } catch {
    clearExpiredSession();
    return false;
  }
}

/**
 * Login - save session
 */
export function saveSession(userData) {
  localStorage.setItem(SESSION_KEY, JSON.stringify({
    ...userData,
    loginAt: new Date().toISOString()
  }));
  updateLastActivity();
  initSession();
}

/**
 * Get current session data
 */
export function getSession() {
  try {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  } catch {
    return null;
  }
}

/**
 * Logout and redirect to login
 */
export function logout(reason = null) {
  // Clear timers
  if (inactivityTimer) {
    clearTimeout(inactivityTimer);
    inactivityTimer = null;
  }

  // Clear API cache
  clearCache();

  // Remove activity listeners
  ACTIVITY_EVENTS.forEach(event => {
    document.removeEventListener(event, handleActivity);
  });

  // Clear session data
  localStorage.removeItem(SESSION_KEY);
  localStorage.removeItem(LAST_ACTIVITY_KEY);

  isInitialized = false;

  // Simpan alasan logout agar login page bisa tampilkan pesan (non-blocking)
  if (reason) {
    sessionStorage.setItem('pos_logout_reason', reason);
  }

  // Redirect to login
  redirectToLogin();
}

/**
 * Redirect to login page
 */
function redirectToLogin() {
  // Clear the app and show login requirement
  window.location.hash = '/login';
  window.location.reload();
}

/**
 * Cleanup on page unload
 */
window.addEventListener('beforeunload', () => {
  if (inactivityTimer) {
    clearTimeout(inactivityTimer);
  }
});
