import { fetchStats, fetchSlowMovingProducts } from '../services/api.js';
import { formatCurrency, formatNumber, formatDate, escapeHtml } from '../utils/format.js';

let topProducts = [];
let slowProducts = [];
let currentInactiveDays = 120;

export async function DashboardPage() {
  const [stats, fetchedSlowProducts] = await Promise.all([
    fetchStats(),
    fetchSlowMovingProducts(currentInactiveDays)
  ]);

  topProducts = stats.topProducts;
  slowProducts = fetchedSlowProducts;

  // Calculate growth percentages
  const salesGrowth = stats.yesterdaySales > 0
    ? ((stats.todaySales - stats.yesterdaySales) / stats.yesterdaySales * 100).toFixed(1)
    : 0;
  const txGrowth = stats.yesterdayTransactions > 0
    ? ((stats.todayTransactions - stats.yesterdayTransactions) / stats.yesterdayTransactions * 100).toFixed(1)
    : 0;

  // Chart Data Preparation
  const chartData = {
    week: stats.weekSales,
    month: stats.monthSales || []
  };

  // Calculate Totals and Trends
  const totalWeek = chartData.week.reduce((a, b) => a + b.amount, 0);
  const totalMonth = chartData.month.reduce((a, b) => a + b.amount, 0);

  // Simple trend calculation (comparing last half vs first half of period for rough trend)
  // or use yesterday vs today from stats if available
  const trendWeek = stats.todaySales >= stats.yesterdaySales ? 'positive' : 'negative';
  const trendWeekPct = stats.yesterdaySales > 0 ? ((stats.todaySales - stats.yesterdaySales) / stats.yesterdaySales * 100).toFixed(1) : 0;

  window.dashboardData = chartData;
  window.currentChartPeriod = 'week';
  window._dashboardStats = stats;

  // Helper to render chart bars
  window.renderChart = (period) => {
    const data = window.dashboardData[period];
    const max = Math.max(...data.map(d => d.amount)) || 1;

    return data.map((d, index) => {
      const height = (d.amount / max) * 100;
      const isToday = period === 'week' && index === data.length - 1;
      return `
        <div class="chart-col${isToday ? ' chart-col-today' : ''}" data-amount="${d.amount}" onclick="handleChartTap(this)">
          <span class="chart-val-label"></span>
          <div class="chart-bar-bg">
            <div class="chart-bar-fill" style="height: ${height}%"></div>
          </div>
          <span class="chart-label">${isToday ? '<strong>' + d.day + '</strong>' : d.day}</span>
        </div>
      `;
    }).join('');
  };

  // Helper to update chart header
  window.updateChartHeader = (period) => {
    const total = period === 'week' ? totalWeek : totalMonth;
    // For 30 days, we might want a different trend logic, but for now we look at general stats
    // or just show total. user reference showed Total + Trend.
    // Let's stick to the visible Total.
    document.getElementById('chart-total-value').textContent = formatCurrency(total);
    document.getElementById('chart-total-label').textContent = period === 'week' ? 'Total 7 Hari' : 'Total 30 Hari';

    // Update active button
    document.querySelectorAll('.chart-filter-btn').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.period === period);
    });

    // Render chart
    document.getElementById('dashboard-chart-container').innerHTML = window.renderChart(period);
    document.getElementById('dashboard-chart-container').className = `chart-container ${period === 'month' ? 'compact-bars' : ''}`;
  };

  setTimeout(() => {
    window.updateChartHeader('week');
  }, 0);


  window.refreshDashboard = async () => {
    window.refreshCurrentPage?.();
  };

  return `
    <div class="page dashboard-page">
      <div class="page-header">
        <h2 class="page-title">
          Dashboard
          <span style="font-size: 11px; font-weight: 500; color: var(--text-muted); margin-top: 4px; display: block; letter-spacing: 0;">
            Data per ${formatDate(stats.fetchedAt)}
          </span>
        </h2>
        <div class="header-actions">
          <button class="btn btn-icon" id="btn-refresh" onclick="refreshDashboard()" title="Segarkan Data" aria-label="Segarkan Data">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path>
            </svg>
          </button>
        </div>
      </div>

      <!-- Summary Cards Row (Profit & Sales Today) -->
      <div class="summary-row">
        <div class="summary-card primary">
           <div class="summary-content">
            <div class="summary-label">Penjualan Hari Ini</div>
            <div class="summary-value">${formatCurrency(stats.todaySales)}</div>
            <div class="summary-change ${salesGrowth >= 0 ? 'positive' : 'negative'}">
              ${salesGrowth >= 0 ? 'Naik' : 'Turun'} ${Math.abs(salesGrowth)}%
            </div>
          </div>
        </div>
        <div class="summary-card profit">
          <div class="summary-content">
            <div class="summary-label">Laba Hari Ini</div>
            <div class="summary-value">${formatCurrency(stats.todayProfit)}</div>
          </div>
        </div>
      </div>

      <!-- Sales Trend Chart Card -->
      <div class="section-card chart-card">
        <div class="chart-header-row">
          <div class="chart-info">
            <h3 class="chart-title">Tren Penjualan</h3>
            <div class="chart-stats">
              <span id="chart-total-label" class="chart-stat-label">Total 7 Hari</span>:
              <span id="chart-total-value" class="chart-stat-value">${formatCurrency(totalWeek)}</span>
              <span class="chart-trend ${trendWeek === 'positive' ? 'positive' : 'negative'}">
                ${trendWeek === 'positive' ? '↗' : '↘'} ${Math.abs(trendWeekPct)}%
              </span>
            </div>
          </div>
          <div class="chart-controls">
            <button class="chart-filter-btn active" data-period="week" onclick="updateChartHeader('week')">7 Hari</button>
            <button class="chart-filter-btn" data-period="month" onclick="updateChartHeader('month')">30 Hari</button>
          </div>
        </div>

        <div id="dashboard-chart-container" class="chart-container">
          <!-- Rendered by JS -->
        </div>
      </div>

      <!-- Quick Stats Grid -->
      <div class="quick-stats">
        <div class="quick-stat" onclick="window.location.hash='/transactions'" style="cursor: pointer">
          <div class="quick-stat-icon">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
          </div>
          <div class="quick-stat-value" data-value="${stats.todayTransactions}">${formatNumber(stats.todayTransactions)}</div>
          <div class="quick-stat-label">Transaksi</div>
        </div>
        <div class="quick-stat">
          <div class="quick-stat-icon">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"/></svg>
          </div>
          <div class="quick-stat-value" data-value="${stats.totalProducts}">${formatNumber(stats.totalProducts)}</div>
          <div class="quick-stat-label">Total Produk</div>
        </div>
        <div class="quick-stat ${stats.lowStockCount > 0 ? 'warning' : ''}" onclick="window.location.hash='/products?filter=low'" style="cursor: pointer">
          <div class="quick-stat-icon">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
          </div>
          <div class="quick-stat-value" data-value="${stats.lowStockCount}">${formatNumber(stats.lowStockCount)}</div>
          <div class="quick-stat-label">Stok Menipis</div>
        </div>
        <div class="quick-stat ${stats.overdueCount > 0 ? 'danger' : ''}" onclick="window.location.hash='/debts'" style="cursor: pointer">
          <div class="quick-stat-icon">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
          </div>
          <div class="quick-stat-value" data-value="${stats.overdueCount}">${formatNumber(stats.overdueCount)}</div>
          <div class="quick-stat-label">Jatuh Tempo</div>
        </div>
      </div>

      <!-- Alerts -->
      ${stats.recentAlerts.length > 0 ? `
        <div class="section-card">
          <div class="section-header">
            <h3 class="section-title">Peringatan</h3>
          </div>
          <div class="alerts-container">
            ${stats.recentAlerts.map(alert => `
              <div class="alert-item ${alert.type}" 
                   onclick="${alert.type === 'lowStock' ? "window.location.hash='/products?filter=low'" : ""}"
                   style="${alert.type === 'lowStock' ? "cursor: pointer" : ""}">
                <div class="alert-icon">
                  ${alert.type === 'lowStock'
      ? `<svg width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24" style="color:var(--warning-dark)"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>`
      : `<svg width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" viewBox="0 0 24 24" style="color:var(--danger)"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>`
    }
                </div>
                <div class="alert-content">
                  <div class="alert-message">${escapeHtml(alert.message)}</div>
                  <div class="alert-time">${alert.time}</div>
                </div>
                ${alert.type === 'lowStock' ? `
                  <div class="alert-action">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                      <path d="M9 5l7 7-7 7"/>
                    </svg>
                  </div>
                ` : ''}
              </div>
            `).join('')}
          </div>
        </div>
      ` : ''}

      <!-- Top Products (Expandable) -->
      <div class="section-card">
        <div class="section-header">
          <h3 class="section-title">Produk Terlaris</h3>
          <span class="list-count" id="top-count">5 dari ${topProducts.length}</span>
        </div>
        <div class="list-container" id="top-products-list">
          ${renderTopProducts(topProducts.slice(0, 5))}
        </div>
        ${topProducts.length > 5 ? `
          <button class="expand-btn" id="btn-expand-top" onclick="toggleTopProducts()">
            <span>Lihat Semua</span>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M4 6l4 4 4-4"/>
            </svg>
          </button>
        ` : ''}
      </div>

    </div>
  `;
}

function renderTopProducts(products) {
  if (products.length === 0) {
    return '<div class="empty-state small">Tidak ada data</div>';
  }
  return products.map((p, i) => `
    <div class="list-item">
      <div class="list-rank">${i + 1}</div>
      <div class="list-content">
        <div class="list-title">${escapeHtml(p.name)}</div>
        <div class="list-subtitle">${p.sold} terjual</div>
      </div>
      <div class="list-value">${formatCurrency(p.revenue)}</div>
    </div>
  `).join('');
}

function renderSlowProducts(products) {
  if (products.length === 0) {
    return '';
  }
  return products.map((p, i) => `
    <div class="list-item slow-item">
      <div class="list-rank danger">${i + 1}</div>
      <div class="list-content">
        <div class="list-title">${escapeHtml(p.name)}</div>
        <div class="list-subtitle">
          Stok: ${p.stock} •
          ${p.lastSold ? `Terakhir: ${p.lastSold}` : 'Belum pernah terjual'}
        </div>
      </div>
      <div class="list-days">
        <span class="days-badge">${p.daysSinceLastSale} hari</span>
      </div>
    </div>
  `).join('');
}

// State for expand/collapse
let topExpanded = false;
let slowExpanded = false;

window.toggleTopProducts = () => {
  topExpanded = !topExpanded;
  const list = document.getElementById('top-products-list');
  const btn = document.getElementById('btn-expand-top');
  const countEl = document.getElementById('top-count');

  if (topExpanded) {
    list.innerHTML = renderTopProducts(topProducts.slice(0, 30));
    btn.innerHTML = `
      <span>Tutup</span>
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M4 10l4-4 4 4"/>
      </svg>
    `;
    btn.classList.add('expanded');
    countEl.textContent = `${Math.min(30, topProducts.length)} dari ${topProducts.length}`;
  } else {
    list.innerHTML = renderTopProducts(topProducts.slice(0, 5));
    btn.innerHTML = `
      <span>Lihat Semua (${topProducts.length})</span>
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M4 6l4 4 4-4"/>
      </svg>
    `;
    btn.classList.remove('expanded');
    countEl.textContent = `5 dari ${topProducts.length}`;
  }
};

window.toggleSlowProducts = () => {
  slowExpanded = !slowExpanded;
  const list = document.getElementById('slow-products-list');
  const btn = document.getElementById('btn-expand-slow');
  const countEl = document.getElementById('slow-count');

  if (slowExpanded) {
    list.innerHTML = renderSlowProducts(slowProducts.slice(0, 30));
    btn.innerHTML = `
      <span>Tutup</span>
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M4 10l4-4 4 4"/>
      </svg>
    `;
    btn.classList.add('expanded');
    countEl.textContent = `${Math.min(30, slowProducts.length)} dari ${slowProducts.length}`;
  } else {
    list.innerHTML = renderSlowProducts(slowProducts.slice(0, 5));
    btn.innerHTML = `
      <span>Lihat Semua (${slowProducts.length})</span>
      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M4 6l4 4 4-4"/>
      </svg>
    `;
    btn.classList.remove('expanded');
    countEl.textContent = `${Math.min(5, slowProducts.length)} dari ${slowProducts.length}`;
  }
};

window.filterSlowProducts = async (days) => {
  currentInactiveDays = parseInt(days);
  slowProducts = await fetchSlowMovingProducts(currentInactiveDays);
  slowExpanded = false;

  const list = document.getElementById('slow-products-list');
  const countEl = document.getElementById('slow-count');
  const daysLabel = document.getElementById('days-label');
  const btnContainer = document.getElementById('btn-expand-slow')?.parentElement;

  daysLabel.textContent = currentInactiveDays;

  if (slowProducts.length === 0) {
    list.innerHTML = `<div class="empty-state small">Tidak ada produk tidak laku dalam ${currentInactiveDays} hari</div>`;
    countEl.textContent = '0';
    if (document.getElementById('btn-expand-slow')) {
      document.getElementById('btn-expand-slow').style.display = 'none';
    }
  } else {
    list.innerHTML = renderSlowProducts(slowProducts.slice(0, 5));
    countEl.textContent = `${Math.min(5, slowProducts.length)} dari ${slowProducts.length}`;

    // Update or show expand button
    let btn = document.getElementById('btn-expand-slow');
    if (slowProducts.length > 5) {
      if (btn) {
        btn.style.display = 'flex';
        btn.innerHTML = `
          <span>Lihat Semua (${slowProducts.length})</span>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M4 6l4 4 4-4"/>
          </svg>
        `;
        btn.classList.remove('expanded');
      }
    } else if (btn) {
      btn.style.display = 'none';
    }
  }
};

window.initDashboard = () => {
  window.handleChartTap = (col) => {
    // Sembunyikan semua label dulu
    document.querySelectorAll('.chart-val-label').forEach(l => {
      l.textContent = '';
      l.classList.remove('visible');
    });

    const amount = parseInt(col.dataset.amount);
    if (amount > 0) {
      const label = col.querySelector('.chart-val-label');
      if (label) {
        label.textContent = formatCurrency(amount);
        label.classList.add('visible');
      }
    }
  };

  window.animateValue = (el, start, end, duration = 600) => {
    if (!el || start === end) { if (el) el.textContent = el.dataset.formatted || end; return; }
    const startTime = performance.now();
    const step = (currentTime) => {
      if (!el.isConnected) return; // elemen sudah di-unmount (navigasi saat animasi berjalan)
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3); // ease-out cubic
      const current = Math.round(start + (end - start) * eased);
      el.textContent = current.toLocaleString('id-ID');
      if (progress < 1) requestAnimationFrame(step);
      else el.textContent = el.dataset.formatted || end.toLocaleString('id-ID');
    };
    requestAnimationFrame(step);
  };

  // Animate quick stat values on load
  requestAnimationFrame(() => {
    document.querySelectorAll('.quick-stat-value[data-value]').forEach(el => {
      const val = parseInt(el.dataset.value);
      if (!isNaN(val)) window.animateValue(el, 0, val);
    });
  });
};
