import { fetchProducts, fetchCategories, updateStock, deleteProduct } from '../services/api.js';
import { formatCurrency, renderEmptyState, escapeHtml } from '../utils/format.js';

let products = [];
let categories = [];
let totalCount = 0;
let currentPage = 1;
const PAGE_SIZE = 20;
let currentFilter = { search: '', categoryId: null, lowStock: false };

export async function ProductsPage(query = {}) {
  // Apply filter from dashboard if present
  if (query.filter === 'low') {
    currentFilter.lowStock = true;
    currentFilter.categoryId = null;
    currentFilter.search = '';
  }

  currentPage = 1;

  // Parallel fetch using Promise.all for speed
  const [result, fetchedCategories] = await Promise.all([
    fetchProducts(currentFilter.search, currentFilter, PAGE_SIZE, 0),
    fetchCategories()
  ]);

  products = result.data || result;
  totalCount = result.total || products.length;
  categories = fetchedCategories;

  const categoryChips = categories.map(c => `
    <button class="chip ${currentFilter.categoryId === c.id ? 'active' : ''}" data-category="${escapeHtml(c.id)}">${escapeHtml(c.name)}</button>
  `).join('');

  return `
    <div class="page products-page">
      <div class="page-header">
        <h2 class="page-title">Produk</h2>
        <div class="header-actions">
          <button class="btn btn-icon" data-action="stock-history" title="Riwayat Stok" aria-label="Riwayat Stok">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
          <button class="btn btn-icon" data-action="add-product" title="Tambah Produk" aria-label="Tambah Produk">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M12 4v16m-8-8h16"/>
            </svg>
          </button>
        </div>
      </div>

      <div class="search-bar">
        <div class="search-wrap">
          <svg class="search-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
          <input type="text" id="product-search" placeholder="Cari produk atau barcode..." class="search-input" value="${escapeHtml(currentFilter.search)}">
        </div>
      </div>

      <div class="filter-chips">
        <button class="chip ${!currentFilter.lowStock && !currentFilter.categoryId ? 'active' : ''}" data-filter="all">Semua</button>
        <button class="chip chip-warning ${currentFilter.lowStock ? 'active' : ''}" data-filter="low">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>
          Stok Rendah
        </button>
        ${categoryChips}
      </div>

      <div class="product-count">
        Menampilkan <span id="product-count-shown">${products.length}</span> dari <span id="product-count-total">${totalCount}</span> produk
      </div>

      <div class="compact-list" id="product-list">
        ${renderProductList(products)}
      </div>

      <div class="load-more-container ${products.length >= totalCount ? 'hidden' : ''}" id="load-more-container">
        <button class="btn btn-outline load-more-btn" id="load-more-btn">Muat Lebih Banyak</button>
      </div>

      <!-- Stock Adjustment Modal -->
      <div class="modal-overlay" id="stock-adjust-modal">
        <div class="product-modal-card">
          <div class="modal-header">
            <h3 class="modal-title" id="stock-adjust-title">Sesuaikan Stok</h3>
            <button class="modal-close" onclick="closeModal('stock-adjust-modal')">&times;</button>
          </div>
          <div class="modal-body">
            <p id="stock-adjust-desc" style="color:var(--text-secondary);margin-bottom:12px;font-size:13px;"></p>
            <div class="form-group">
              <label>Jumlah</label>
              <input type="number" id="stock-adjust-qty" min="1" value="1" class="search-input">
            </div>
          </div>
          <div class="modal-footer">
            <button class="btn btn-outline" onclick="closeModal('stock-adjust-modal')">Batal</button>
            <button class="btn btn-primary" id="btn-confirm-stock-adjust">Konfirmasi</button>
          </div>
        </div>
      </div>
    </div>
  `;
}

function renderProductItems(items) {
  return items.map(p => {
    const stockLevel = p.stock < 5 ? 'danger' : p.stock < 15 ? 'warning' : '';
    const nameParts = p.name.match(/^(\d+\w*\.\w+)\s+(.+)$/);
    const codePrefix = nameParts ? nameParts[1] : null;
    const productName = nameParts ? nameParts[2] : p.name;
    return `
      <div class="compact-item ${stockLevel}" data-product-id="${p.id}">
        <div class="compact-info" data-action="edit-product" data-product-id="${p.id}">
          ${codePrefix ? `<span class="compact-code">${escapeHtml(codePrefix)}</span>` : ''}
          <span class="compact-name">${escapeHtml(productName)}</span>
          <span class="compact-meta">${escapeHtml(p.category) || 'Umum'} • ${formatCurrency(p.price)}</span>
        </div>
        <div class="compact-actions">
          <div class="stock-ctrl-group">
            <button class="stock-ctrl-btn" data-action="decrease-stock" data-product-id="${p.id}" aria-label="Kurangi Stok">−</button>
            <div class="stock-display">
              <span class="stock-badge ${stockLevel}">${p.stock}</span>
              <span class="stock-unit">${escapeHtml(p.unit) || 'pcs'}</span>
            </div>
            <button class="stock-ctrl-btn" data-action="increase-stock" data-product-id="${p.id}" aria-label="Tambah Stok">+</button>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

function renderProductList(items) {
  if (!items.length) {
    if (currentFilter.lowStock) {
      return renderEmptyState(
        `<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>`,
        'Semua stok dalam kondisi baik',
        null, null
      );
    }
    return renderEmptyState(
      `<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"/></svg>`,
      'Tidak ada produk ditemukan',
      'Tambah Produk',
      "window.location.hash='/products/add'"
    );
  }

  return renderProductItems(items);
}

async function refreshProducts() {
  currentPage = 1;
  const result = await fetchProducts(currentFilter.search, currentFilter, PAGE_SIZE, 0);
  products = result.data || result;
  totalCount = result.total || products.length;

  const listEl = document.getElementById('product-list');
  if (listEl) {
    listEl.innerHTML = renderProductList(products);
  }
  updateProductCount();

  const loadMoreContainer = document.getElementById('load-more-container');
  if (loadMoreContainer) {
    loadMoreContainer.classList.toggle('hidden', products.length >= totalCount);
  }
}

async function loadMoreProducts() {
  const btn = document.getElementById('load-more-btn');
  if (btn) {
    btn.disabled = true;
    btn.textContent = 'Memuat...';
  }

  try {
    const nextOffset = currentPage * PAGE_SIZE;
    const result = await fetchProducts(currentFilter.search, currentFilter, PAGE_SIZE, nextOffset);
    const newItems = result.data || result;

    if (newItems.length > 0) {
      products = [...products, ...newItems];
      currentPage++;

      const listEl = document.getElementById('product-list');
      if (listEl) {
        // Append new items to the DOM instead of full re-render
        listEl.insertAdjacentHTML('beforeend', renderProductItems(newItems));
      }
      updateProductCount();
    }

    const loadMoreContainer = document.getElementById('load-more-container');
    if (loadMoreContainer) {
      loadMoreContainer.classList.toggle('hidden', products.length >= totalCount);
    }
  } catch (error) {
    console.error('Error loading more products:', error);
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.textContent = 'Muat Lebih Banyak';
    }
  }
}

function updateProductCount() {
  const shownEl = document.getElementById('product-count-shown');
  const totalEl = document.getElementById('product-count-total');
  if (shownEl) shownEl.textContent = products.length;
  if (totalEl) totalEl.textContent = totalCount;
}

window.initProducts = async (query = {}) => {
  const pageEl = document.querySelector('.products-page');
  if (!pageEl) return;

  // Pindahkan modal ke body agar position:fixed bekerja relatif ke viewport,
  // bukan relatif ke .page-instance yang punya CSS transform.
  const stockModal = document.getElementById('stock-adjust-modal');
  if (stockModal && stockModal.parentElement !== document.body) {
    document.body.appendChild(stockModal);
  }

  // Apply filter from dashboard (hanya jika chip belum aktif, mencegah double-fetch saat first render)
  if (query.filter === 'low') {
    const lowChip = document.querySelector('.chip[data-filter="low"]');
    if (!lowChip?.classList.contains('active')) {
      currentFilter.lowStock = true;
      currentFilter.categoryId = null;
      currentFilter.search = '';
      const searchInput = document.getElementById('product-search');
      if (searchInput) searchInput.value = '';
      document.querySelectorAll('.chip').forEach(c => c.classList.remove('active'));
      lowChip?.classList.add('active');
      await refreshProducts();
    }
  }

  // Event delegation
  pageEl.addEventListener('click', async (e) => {
    const target = e.target.closest('[data-action]');
    if (!target) return;

    const action = target.dataset.action;
    const productId = target.dataset.productId;

    switch (action) {
      case 'stock-history':
        window.location.hash = '/stock-history';
        break;

      case 'add-product':
        window.location.hash = '/products/add';
        break;

      case 'edit-product':
        if (productId) {
          window.location.hash = `/products/edit?id=${productId}`;
        }
        break;

      case 'increase-stock':
        if (productId) {
          await handleStockAdjustment(parseInt(productId), 1);
        }
        break;

      case 'decrease-stock':
        if (productId) {
          await handleStockAdjustment(parseInt(productId), -1);
        }
        break;
    }
  });

  // Category filter
  pageEl.addEventListener('click', async (e) => {
    const chip = e.target.closest('.chip');
    if (!chip) return;

    const categoryId = chip.dataset.category;
    const filter = chip.dataset.filter;

    if (filter === 'all') {
      currentFilter.categoryId = null;
      currentFilter.lowStock = false;
      currentFilter.sortBy = 'name';
      currentFilter.sortOrder = 'asc';
    } else if (filter === 'low') {
      currentFilter.categoryId = null;
      currentFilter.lowStock = true;
      currentFilter.sortBy = 'stock';
      currentFilter.sortOrder = 'asc';
    } else if (categoryId) {
      currentFilter.categoryId = parseInt(categoryId);
      currentFilter.lowStock = false;
      currentFilter.sortBy = 'name';
      currentFilter.sortOrder = 'asc';
    }

    // Update chip active states
    document.querySelectorAll('.chip').forEach(c => c.classList.remove('active'));
    chip.classList.add('active');

    await refreshProducts();
  });

  // Search input
  const searchInput = document.getElementById('product-search');
  let searchTimeout;
  searchInput?.addEventListener('input', (e) => {
    clearTimeout(searchTimeout);
    searchTimeout = setTimeout(async () => {
      currentFilter.search = e.target.value;
      await refreshProducts();
    }, 150);
  });

  // Load more button
  const loadMoreBtn = document.getElementById('load-more-btn');
  loadMoreBtn?.addEventListener('click', async () => {
    await loadMoreProducts();
  });

  // Stock adjust modal confirm — remove dulu sebelum add agar tidak duplikat
  // saat initProducts dipanggil ulang (cached page re-init)
  const btnConfirmAdj = document.getElementById('btn-confirm-stock-adjust');
  btnConfirmAdj?.removeEventListener('click', confirmStockAdjustment);
  btnConfirmAdj?.addEventListener('click', confirmStockAdjustment);

  const qtyInput = document.getElementById('stock-adjust-qty');
  qtyInput?.removeEventListener('keydown', _onQtyKeydown);
  qtyInput?.addEventListener('keydown', _onQtyKeydown);
};

let _pendingStockAdjust = null;

function _onQtyKeydown(e) {
  if (e.key === 'Enter') confirmStockAdjustment();
}

function handleStockAdjustment(productId, direction) {
  const product = products.find(p => p.id === productId);
  if (!product) return;

  const type = direction > 0 ? 'Penambahan' : 'Pengurangan';
  _pendingStockAdjust = { productId, direction, type };

  const titleEl = document.getElementById('stock-adjust-title');
  const descEl = document.getElementById('stock-adjust-desc');
  const qtyEl = document.getElementById('stock-adjust-qty');

  if (titleEl) titleEl.textContent = `${type} Stok`;
  if (descEl) descEl.textContent = `Produk: ${product.name} (stok saat ini: ${product.stock})`;
  if (qtyEl) { qtyEl.value = '1'; qtyEl.focus(); }

  openModal('stock-adjust-modal');
}

async function confirmStockAdjustment() {
  if (!_pendingStockAdjust) return;

  const { productId, direction, type } = _pendingStockAdjust;
  const product = products.find(p => p.id === productId);
  if (!product) return;

  const qtyEl = document.getElementById('stock-adjust-qty');
  const qty = parseInt(qtyEl?.value || '0');

  if (isNaN(qty) || qty <= 0) {
    window.showToast?.('Jumlah harus berupa angka lebih dari 0', 'warning');
    return;
  }

  const adjustQty = direction * qty;
  const newStock = product.stock + adjustQty;

  if (newStock < 0) {
    window.showToast?.('Stok tidak bisa kurang dari 0', 'error');
    return;
  }

  closeModal('stock-adjust-modal');
  _pendingStockAdjust = null;

  try {
    await updateStock(productId, adjustQty, `${type} manual via PWA`);

    product.stock = newStock;

    const stockBadge = document.querySelector(`[data-product-id="${productId}"] .stock-badge`);
    if (stockBadge) {
      stockBadge.textContent = newStock;
      stockBadge.classList.remove('animating');
      void stockBadge.offsetWidth; // force reflow
      stockBadge.classList.add('animating');
      stockBadge.addEventListener('animationend', () => stockBadge.classList.remove('animating'), { once: true });
      stockBadge.classList.remove('warning', 'danger');
      if (newStock < 5) stockBadge.classList.add('danger');
      else if (newStock < 15) stockBadge.classList.add('warning');
    }

    window.showToast?.(`Stok berhasil diperbarui: ${newStock}`, 'success');
  } catch (error) {
    console.error('Error adjusting stock:', error);
    window.showToast?.('Gagal mengubah stok: ' + error.message, 'error');
  }
}
