import { fetchDebts, fetchDebtSummary, addPayment, fetchTransactionById } from '../services/api.js';
import { formatCurrency, formatDate, renderEmptyState, escapeHtml } from '../utils/format.js';

let debts = [];
let summary = {};
let currentFilter = { status: 'all', search: '', overdue: false };
let selectedDebt = null;

export async function DebtsPage() {
  const [fetchedDebts, fetchedSummary] = await Promise.all([
    fetchDebts(),
    fetchDebtSummary()
  ]);

  debts = fetchedDebts;
  summary = fetchedSummary;

  return `
    <div class="page debts-page">
      <h2 class="page-title">Piutang</h2>

      <!-- Summary Cards -->
      <div class="debt-summary-cards">
        <div class="debt-summary-card primary">
          <div class="debt-card-label">Total Piutang</div>
          <div class="debt-card-value">${formatCurrency(summary.totalOutstanding)}</div>
          <div class="debt-card-sub">${summary.totalCustomers} customer</div>
        </div>
        <div class="debt-summary-card ${summary.overdueCount > 0 ? 'danger' : 'success'}">
          <div class="debt-card-label">Jatuh Tempo</div>
          <div class="debt-card-value">${summary.overdueCount}</div>
          <div class="debt-card-sub">${formatCurrency(summary.overdueAmount)}</div>
        </div>
      </div>

      <!-- Status Breakdown -->
      <div class="status-breakdown">
        <div class="status-item" data-status="pending">
          <span class="status-dot pending"></span>
          <span class="status-label">Pending</span>
          <span class="status-count">${summary.byStatus.pending.count}</span>
        </div>
        <div class="status-item" data-status="hutang">
          <span class="status-dot hutang"></span>
          <span class="status-label">Hutang</span>
          <span class="status-count">${summary.byStatus.hutang.count}</span>
        </div>
        <div class="status-item" data-status="cicilan">
          <span class="status-dot cicilan"></span>
          <span class="status-label">Cicilan</span>
          <span class="status-count">${summary.byStatus.cicilan.count}</span>
        </div>
      </div>

      <div class="search-bar">
        <input type="text" id="debt-search" placeholder="Cari customer atau ID transaksi..." class="search-input">
      </div>

      <div class="filter-chips">
        <button class="chip active" data-filter="all">Semua</button>
        <button class="chip" data-filter="overdue">Jatuh Tempo</button>
        <button class="chip" data-filter="pending">Pending</button>
        <button class="chip" data-filter="hutang">Hutang</button>
        <button class="chip" data-filter="cicilan">Cicilan</button>
      </div>

      <div class="compact-list" id="debt-list">
        ${renderDebtList(debts)}
      </div>

      <!-- Debt Detail Modal -->
      <div class="modal-overlay" id="debt-detail-modal">
        <div class="product-modal-card modal-lg">
          <div class="modal-header">
            <h3 class="modal-title">Detail Piutang</h3>
            <button class="modal-close" onclick="closeModal('debt-detail-modal')">&times;</button>
          </div>
          <div class="modal-body" id="debt-detail-content">
            <!-- Filled by JS -->
          </div>
          <div class="modal-footer">
            <button class="btn btn-outline" onclick="closeModal('debt-detail-modal')">Tutup</button>
            <button class="btn" id="btn-add-payment">Tambah Pembayaran</button>
          </div>
        </div>
      </div>

      <!-- Add Payment Modal -->
      <div class="modal-overlay" id="payment-modal">
        <div class="product-modal-card">
          <div class="modal-header">
            <h3 class="modal-title">Tambah Pembayaran</h3>
            <button class="modal-close" onclick="closeModal('payment-modal')">&times;</button>
          </div>
          <div class="modal-body">
            <div class="payment-info-header">
              <div class="payment-customer" id="payment-customer">-</div>
              <div class="payment-remaining">
                Sisa: <strong id="payment-remaining">Rp 0</strong>
              </div>
            </div>
            <form id="payment-form">
              <div class="form-group">
                <label>Jumlah Bayar</label>
                <input type="number" id="payment-amount" required placeholder="0" min="1">
              </div>
              <div class="form-group">
                <label>Metode Pembayaran</label>
                <select id="payment-method">
                  <option value="cash">Cash</option>
                  <option value="transfer">Transfer</option>
                  <option value="qris">QRIS</option>
                </select>
              </div>
              <div class="form-group">
                <label>Catatan (opsional)</label>
                <input type="text" id="payment-notes" placeholder="Catatan pembayaran">
              </div>
            </form>
          </div>
          <div class="modal-footer">
            <button class="btn btn-outline" onclick="closeModal('payment-modal')">Batal</button>
            <button type="submit" form="payment-form" class="btn">Simpan Pembayaran</button>
          </div>
        </div>
      </div>
    </div>
  `;
}

function renderDebtList(items) {
  if (items.length === 0) {
    return renderEmptyState(
      `<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>`,
      'Tidak ada piutang aktif',
      null, null
    );
  }
  return items.map(debt => {
    const statusConfig = {
      pending: { class: 'info', label: 'Pending' },
      hutang: { class: 'warning', label: 'Hutang' },
      cicilan: { class: 'purple', label: 'Cicilan' }
    };
    const status = statusConfig[debt.status] || statusConfig.hutang;

    const overdueClass = debt.isOverdue ? 'overdue' : '';
    const progress = ((debt.totalPaid / debt.total) * 100).toFixed(0);

    return `
      <div class="debt-card ${overdueClass}" onclick="showDebtDetail('${debt.id}')">
        <div class="debt-card-header">
          <div class="debt-customer">${escapeHtml(debt.customerName)}</div>
          <span class="badge badge-${status.class}">${status.label}</span>
        </div>
        <div class="debt-card-body">
          <div class="debt-tx-id">#${debt.id}</div>
          <div class="debt-dates">
            <span>Transaksi: ${formatDate(debt.date)}</span>
            <span>Jatuh tempo: ${debt.dueDate}</span>
          </div>
          ${debt.isOverdue ? `
            <div class="debt-overdue-badge">
              Terlambat ${debt.daysOverdue} hari
            </div>
          ` : ''}
        </div>
        <div class="debt-card-footer">
          <div class="debt-amounts">
            <div class="debt-total">Total: ${formatCurrency(debt.total)}</div>
            <div class="debt-remaining">Sisa: <strong>${formatCurrency(debt.remainingBalance)}</strong></div>
          </div>
          <div class="debt-progress">
            <div class="progress-bar">
              <div class="progress-fill" style="width: ${progress}%"></div>
            </div>
            <div class="progress-text">${progress}% terbayar</div>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

window.showDebtDetail = async (id) => {
  const tx = await fetchTransactionById(id);
  selectedDebt = debts.find(d => d.id === id);
  if (!tx || !selectedDebt) return;

  const statusConfig = {
    pending: { class: 'info', label: 'Pending' },
    hutang: { class: 'warning', label: 'Hutang' },
    cicilan: { class: 'purple', label: 'Cicilan' }
  };
  const status = statusConfig[selectedDebt.status] || statusConfig.hutang;
  const progress = ((selectedDebt.totalPaid / selectedDebt.total) * 100).toFixed(0);

  // Payment history
  let paymentSection = '';
  if (tx.paymentHistory && tx.paymentHistory.length > 0) {
    const paymentList = tx.paymentHistory.map(p => `
      <div class="payment-row">
        <div class="payment-info">
          <div class="payment-date">${p.date}</div>
          <div class="payment-method">${p.method} - ${escapeHtml(p.receivedBy)}</div>
          ${p.notes ? `<div class="payment-notes">${escapeHtml(p.notes)}</div>` : ''}
        </div>
        <div class="payment-amount">${formatCurrency(p.amount)}</div>
      </div>
    `).join('');

    paymentSection = `
      <div class="detail-section">
        <h4 class="section-title">Riwayat Pembayaran</h4>
        <div class="payment-list">
          ${paymentList}
        </div>
      </div>
    `;
  }

  document.getElementById('debt-detail-content').innerHTML = `
    <div class="detail-section">
      <div class="detail-header">
        <div>
          <h4 class="detail-name">${escapeHtml(selectedDebt.customerName)}</h4>
          <div class="detail-phone">${escapeHtml(selectedDebt.customerPhone) || '-'}</div>
        </div>
        <span class="badge badge-${status.class}">${status.label}</span>
      </div>
      ${selectedDebt.isOverdue ? `
        <div class="overdue-alert">
          Terlambat ${selectedDebt.daysOverdue} hari dari jatuh tempo
        </div>
      ` : ''}
      <div class="detail-info">
        <div class="detail-row">
          <span class="detail-label">ID Transaksi</span>
          <span class="detail-value">#${selectedDebt.id}</span>
        </div>
        <div class="detail-row">
          <span class="detail-label">Tanggal Transaksi</span>
          <span class="detail-value">${formatDate(selectedDebt.date)}</span>
        </div>
        <div class="detail-row">
          <span class="detail-label">Jatuh Tempo</span>
          <span class="detail-value ${selectedDebt.isOverdue ? 'text-danger' : ''}">${selectedDebt.dueDate}</span>
        </div>
      </div>
    </div>

    <div class="detail-section">
      <h4 class="section-title">Ringkasan Pembayaran</h4>
      <div class="payment-summary">
        <div class="payment-summary-row">
          <span>Total Tagihan</span>
          <span>${formatCurrency(selectedDebt.total)}</span>
        </div>
        <div class="payment-summary-row">
          <span>Sudah Dibayar</span>
          <span class="text-success">${formatCurrency(selectedDebt.totalPaid)}</span>
        </div>
        <div class="payment-summary-row highlight">
          <span>Sisa Tagihan</span>
          <span>${formatCurrency(selectedDebt.remainingBalance)}</span>
        </div>
      </div>
      <div class="debt-progress large">
        <div class="progress-bar">
          <div class="progress-fill" style="width: ${progress}%"></div>
        </div>
        <div class="progress-text">${progress}% terbayar</div>
      </div>
    </div>

    ${paymentSection}
  `;

  openModal('debt-detail-modal');
};

window.initDebts = () => {
  const chips = document.querySelectorAll('.chip');
  const searchInput = document.getElementById('debt-search');
  const btnAddPayment = document.getElementById('btn-add-payment');
  const paymentForm = document.getElementById('payment-form');

  // Filter chips
  chips.forEach(chip => {
    chip.addEventListener('click', async () => {
      chips.forEach(c => c.classList.remove('active'));
      chip.classList.add('active');
      // Bersihkan active state dari status-breakdown saat chip diklik
      document.querySelectorAll('.status-item').forEach(s => s.classList.remove('active'));

      const filter = chip.dataset.filter;
      if (filter === 'all') {
        currentFilter = { status: 'all', search: currentFilter.search, overdue: false };
      } else if (filter === 'overdue') {
        currentFilter.overdue = true;
        currentFilter.status = 'all';
      } else {
        currentFilter.status = filter;
        currentFilter.overdue = false;
      }
      await refreshDebts();
    });
  });

  // Status breakdown items (di atas filter chips)
  document.querySelectorAll('.status-item').forEach(item => {
    item.addEventListener('click', async () => {
      const status = item.dataset.status;

      document.querySelectorAll('.status-item').forEach(s => s.classList.remove('active'));
      item.classList.add('active');

      // Sync dengan chip filter
      chips.forEach(c => c.classList.remove('active'));
      const matchingChip = document.querySelector(`.chip[data-filter="${status}"]`);
      if (matchingChip) matchingChip.classList.add('active');

      currentFilter.status = status;
      currentFilter.overdue = false;
      await refreshDebts();
    });
  });

  // Search
  searchInput?.addEventListener('input', async (e) => {
    currentFilter.search = e.target.value;
    await refreshDebts();
  });

  // Add payment button
  btnAddPayment?.addEventListener('click', () => {
    if (!selectedDebt) return;
    closeModal('debt-detail-modal');

    document.getElementById('payment-customer').textContent = selectedDebt.customerName;
    document.getElementById('payment-remaining').textContent = formatCurrency(selectedDebt.remainingBalance);
    document.getElementById('payment-amount').max = selectedDebt.remainingBalance;
    document.getElementById('payment-amount').value = '';
    document.getElementById('payment-method').value = 'cash';
    document.getElementById('payment-notes').value = '';

    openModal('payment-modal');
  });

  // Payment form submit
  paymentForm?.addEventListener('submit', async (e) => {
    e.preventDefault();
    if (!selectedDebt) return;

    const amount = parseInt(document.getElementById('payment-amount').value);
    const method = document.getElementById('payment-method').value;
    const notes = document.getElementById('payment-notes').value;

    if (amount > selectedDebt.remainingBalance) {
      window.showToast?.('Jumlah pembayaran melebihi sisa tagihan', 'warning');
      return;
    }

    await addPayment(selectedDebt.id, amount, method, notes);
    closeModal('payment-modal');
    await refreshDebts();
    summary = await fetchDebtSummary();
    updateSummaryDisplay();
  });
};

async function refreshDebts() {
  debts = await fetchDebts(currentFilter);
  document.getElementById('debt-list').innerHTML = renderDebtList(debts);
}

function updateSummaryDisplay() {
  const cards = document.querySelectorAll('.debt-summary-card');
  if (cards.length >= 2) {
    const cardTotal = cards[0];
    const valTotal = cardTotal.querySelector('.debt-card-value');
    const subTotal = cardTotal.querySelector('.debt-card-sub');
    if (valTotal) valTotal.textContent = formatCurrency(summary.totalOutstanding);
    if (subTotal) subTotal.textContent = `${summary.totalCustomers} customer`;

    const cardOverdue = cards[1];
    const valOverdue = cardOverdue.querySelector('.debt-card-value');
    const subOverdue = cardOverdue.querySelector('.debt-card-sub');
    if (valOverdue) valOverdue.textContent = summary.overdueCount;
    if (subOverdue) subOverdue.textContent = formatCurrency(summary.overdueAmount);

    if (summary.overdueCount > 0) {
      cardOverdue.classList.remove('success');
      cardOverdue.classList.add('danger');
    } else {
      cardOverdue.classList.remove('danger');
      cardOverdue.classList.add('success');
    }
  }
}
