// Chart.js Wrapper untuk POS Admin
// Visualisasi data penjualan, trend, dan statistik

import Chart from 'chart.js/auto';

/**
 * Render line chart untuk tren penjualan
 * @param {HTMLCanvasElement} canvas - Element canvas
 * @param {Array} data - Array {day, amount}
 */
export function renderSalesChart(canvas, data) {
  const ctx = canvas.getContext('2d');
  
  // Gradient fill
  const gradient = ctx.createLinearGradient(0, 0, 0, 200);
  gradient.addColorStop(0, 'rgba(16, 185, 129, 0.3)');
  gradient.addColorStop(1, 'rgba(16, 185, 129, 0)');
  
  return new Chart(ctx, {
    type: 'line',
    data: {
      labels: data.map(d => d.day),
      datasets: [{
        label: 'Penjualan',
        data: data.map(d => d.amount),
        borderColor: '#10b981',
        backgroundColor: gradient,
        borderWidth: 2,
        fill: true,
        tension: 0.4,
        pointRadius: 3,
        pointBackgroundColor: '#10b981',
        pointBorderColor: '#fff',
        pointBorderWidth: 2
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          padding: 10,
          cornerRadius: 8,
          callbacks: {
            label: (context) => {
              return 'Rp ' + context.parsed.y.toLocaleString('id-ID');
            }
          }
        }
      },
      scales: {
        x: {
          grid: { display: false },
          ticks: { color: '#9ca3af', font: { size: 11 } }
        },
        y: {
          beginAtZero: true,
          grid: { color: 'rgba(255, 255, 255, 0.05)' },
          ticks: {
            color: '#9ca3af',
            font: { size: 10 },
            callback: (value) => {
              if (value >= 1000000) return (value / 1000000).toFixed(1) + 'jt';
              if (value >= 1000) return (value / 1000).toFixed(0) + 'rb';
              return value;
            }
          }
        }
      }
    }
  });
}

/**
 * Render bar chart untuk kategori produk
 * @param {HTMLCanvasElement} canvas - Element canvas
 * @param {Array} data - Array {category, amount, count}
 */
export function renderCategoryChart(canvas, data) {
  const ctx = canvas.getContext('2d');
  
  return new Chart(ctx, {
    type: 'bar',
    data: {
      labels: data.map(d => d.category),
      datasets: [{
        label: 'Penjualan',
        data: data.map(d => d.amount),
        backgroundColor: [
          '#10b981', '#3b82f6', '#f59e0b', '#ef4444',
          '#8b5cf6', '#ec4899', '#06b6d4', '#84cc16'
        ],
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          padding: 10,
          cornerRadius: 8,
          callbacks: {
            label: (context) => {
              return 'Rp ' + context.parsed.y.toLocaleString('id-ID');
            }
          }
        }
      },
      scales: {
        x: {
          grid: { display: false },
          ticks: { color: '#9ca3af', font: { size: 10 } }
        },
        y: {
          beginAtZero: true,
          grid: { color: 'rgba(255, 255, 255, 0.05)' },
          ticks: {
            color: '#9ca3af',
            font: { size: 10 },
            callback: (value) => {
              if (value >= 1000000) return (value / 1000000).toFixed(1) + 'jt';
              if (value >= 1000) return (value / 1000).toFixed(0) + 'rb';
              return value;
            }
          }
        }
      }
    }
  });
}

/**
 * Render doughnut chart untuk metode pembayaran
 * @param {HTMLCanvasElement} canvas - Element canvas
 * @param {Object} data - { cash, transfer, qris, debit }
 */
export function renderPaymentChart(canvas, data) {
  const ctx = canvas.getContext('2d');
  
  const total = data.cash + data.transfer + data.qris + data.debit;
  
  return new Chart(ctx, {
    type: 'doughnut',
    data: {
      labels: ['Tunai', 'Transfer', 'QRIS', 'Kartu'],
      datasets: [{
        data: [data.cash, data.transfer, data.qris, data.debit],
        backgroundColor: ['#10b981', '#3b82f6', '#f59e0b', '#8b5cf6'],
        borderWidth: 0,
        hoverOffset: 4
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '70%',
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            color: '#9ca3af',
            font: { size: 11 },
            usePointStyle: true,
            padding: 15
          }
        },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          padding: 10,
          cornerRadius: 8,
          callbacks: {
            label: (context) => {
              const value = context.parsed;
              const percentage = total > 0 ? ((value / total) * 100).toFixed(1) : 0;
              return `${context.label}: Rp ${value.toLocaleString('id-ID')} (${percentage}%)`;
            }
          }
        }
      }
    }
  });
}

/**
 * Destroy chart instance untuk cleanup
 */
export function destroyChart(chart) {
  if (chart) {
    chart.destroy();
  }
}
