// ─── Skeleton HTML per halaman ──────────────────────────────
// Ditampilkan SEGERA sebelum async fetch selesai agar user
// tidak melihat layar kosong saat navigasi ke halaman baru.
function getSkeletonHTML(path) {
  // Helper: buat N buah block shimmer
  const rows = (n, h = 52, mb = 6, r = 'var(--radius-sm)') =>
    Array.from({ length: n }, () =>
      `<span class="sk" style="width:100%;height:${h}px;margin-bottom:${mb}px;border-radius:${r};"></span>`
    ).join('');

  const chips = (widths) =>
    widths.map(w =>
      `<span class="sk sk-pill" style="flex-shrink:0;width:${w}px;height:30px;"></span>`
    ).join('');

  switch (path) {
    case '/':
      return `
        <div class="page dashboard-page">
          <div class="page-header">
            <span class="sk" style="width:110px;height:24px;border-radius:6px;"></span>
          </div>
          <div class="section-card chart-card">
            <span class="sk" style="width:55%;height:15px;margin-bottom:8px;"></span>
            <span class="sk" style="width:28%;height:12px;margin-bottom:20px;"></span>
            <span class="sk" style="width:100%;height:138px;border-radius:var(--radius-md);"></span>
          </div>
          <div class="quick-stats">
            ${rows(4, 64, 0, 'var(--radius-md)')}
          </div>
          <div class="summary-row">
            <span class="sk" style="height:78px;border-radius:var(--radius-md);"></span>
            <span class="sk" style="height:78px;border-radius:var(--radius-md);"></span>
          </div>
          <div class="section-card">
            <span class="sk" style="width:48%;height:15px;margin-bottom:16px;"></span>
            ${rows(5, 52, 6)}
          </div>
        </div>`;

    case '/products':
      return `
        <div class="page products-page">
          <div class="page-header">
            <span class="sk" style="width:80px;height:24px;border-radius:6px;"></span>
          </div>
          <span class="sk" style="width:100%;height:42px;margin-bottom:12px;border-radius:var(--radius-md);"></span>
          <div style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap;">
            ${chips([70, 90, 80, 75, 65])}
          </div>
          ${rows(8, 62, 6)}
        </div>`;

    case '/transactions':
      return `
        <div class="page transactions-page">
          <span class="sk" style="width:110px;height:24px;border-radius:6px;margin-bottom:16px;"></span>
          <span class="sk" style="width:100%;height:42px;margin-bottom:10px;border-radius:var(--radius-md);"></span>
          <div style="display:flex;gap:8px;margin-bottom:12px;overflow:hidden;">
            ${chips([60, 72, 78, 72, 60, 55])}
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:16px;">
            <span class="sk" style="height:50px;border-radius:var(--radius-md);"></span>
            <span class="sk" style="height:50px;border-radius:var(--radius-md);"></span>
          </div>
          ${rows(5, 72, 8, 'var(--radius-md)')}
        </div>`;

    case '/reports':
      return `
        <div class="page reports-page">
          <span class="sk" style="width:100px;height:24px;border-radius:6px;margin-bottom:16px;"></span>
          <div style="display:flex;gap:8px;margin-bottom:16px;">
            ${chips([80, 80])}
          </div>
          <span class="sk" style="width:100%;height:220px;border-radius:var(--radius-md);margin-bottom:16px;"></span>
          <span class="sk" style="width:100%;height:180px;border-radius:var(--radius-md);margin-bottom:16px;"></span>
          <span class="sk" style="width:100%;height:180px;border-radius:var(--radius-md);margin-bottom:16px;"></span>
          <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:12px;">
            ${Array.from({ length: 4 }, () =>
        `<span class="sk" style="height:80px;border-radius:var(--radius-md);"></span>`
      ).join('')}
          </div>
        </div>`;

    case '/debts':
      return `
        <div class="page debts-page">
          <span class="sk" style="width:90px;height:24px;border-radius:6px;margin-bottom:16px;"></span>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px;">
            ${Array.from({ length: 4 }, () =>
        `<span class="sk" style="height:78px;border-radius:var(--radius-md);"></span>`
      ).join('')}
          </div>
          <div style="display:flex;gap:8px;margin-bottom:16px;overflow:hidden;">
            ${chips([65, 80, 75, 70])}
          </div>
          ${rows(5, 72, 8, 'var(--radius-md)')}
        </div>`;

    case '/profile':
      return `
        <div class="page profile-page">
          <div style="display:flex;align-items:center;gap:16px;padding:20px;background:var(--surface);border-radius:var(--radius-lg);margin-bottom:20px;border:1px solid var(--border-light);">
            <span class="sk" style="width:60px;height:60px;border-radius:50%;flex-shrink:0;"></span>
            <div style="flex:1;">
              <span class="sk" style="width:55%;height:17px;margin-bottom:8px;"></span>
              <span class="sk" style="width:38%;height:13px;"></span>
            </div>
          </div>
          ${[1, 2].map(() => `
            <div class="section-card" style="margin-bottom:12px;">
              <span class="sk" style="width:42%;height:15px;margin-bottom:14px;"></span>
              ${rows(3, 46, 6)}
            </div>`).join('')}
        </div>`;

    default:
      return `
        <div class="page">
          <span class="sk" style="width:130px;height:24px;border-radius:6px;margin-bottom:20px;"></span>
          ${[1, 2, 3].map(() => `
            <div class="section-card" style="margin-bottom:12px;">
              <span class="sk" style="width:44%;height:15px;margin-bottom:14px;"></span>
              ${rows(3, 48, 6)}
            </div>`).join('')}
        </div>`;
  }
}

const routes = {
  '/': DashboardPage,
  '/products': ProductsPage,
  '/products/add': ProductFormPage,
  '/products/edit': ProductFormPage,
  '/transactions': TransactionsPage,
  '/debts': DebtsPage,
  '/profile': ProfilePage,
  '/login': LoginPage,
  '/stock-history': StockHistoryPage,
  '/users': UserActivityPage,
  '/reports': ReportsPage
};

const pageCache = new Map(); // Store HTMLElement for each path
let appInitialized = false;
let currentPath = null;

const PAGE_LOAD_TIMEOUT = 15000; // ms sebelum skeleton diganti error state

function withPageTimeout(promise) {
  return Promise.race([
    promise,
    new Promise((_, reject) =>
      setTimeout(() => reject(new Error('__TIMEOUT__')), PAGE_LOAD_TIMEOUT)
    )
  ]);
}

// Hapus halaman dari cache lalu re-route, sehingga data di-fetch ulang dari awal
window.retryCurrentPage = () => {
  if (currentPath) pageCache.delete(currentPath);
  router();
};

function getRoute() {
  const hash = window.location.hash.slice(1) || '/';
  const [path, query] = hash.split('?');
  return { path: path || '/', query: parseQuery(query) };
}

function parseQuery(queryString) {
  if (!queryString) return {};
  return queryString.split('&').reduce((acc, part) => {
    const [key, value] = part.split('=');
    try {
      if (key) acc[decodeURIComponent(key)] = decodeURIComponent(value || '');
    } catch {
      // Abaikan segment yang malformed (URIError dari decodeURIComponent)
    }
    return acc;
  }, {});
}

async function router() {
  if (!appInitialized) return;

  const { path, query } = getRoute();
  if (path === currentPath && path !== '/products/edit' && !(path === '/products' && query.filter)) return; // Avoid redundant navigation

  // Check if user is logged in (except for login page)
  if (path !== '/login' && !isLoggedIn()) {
    window.location.hash = '/login';
    return;
  }

  // If logged in and trying to access login, redirect to dashboard
  if (path === '/login' && isLoggedIn()) {
    window.location.hash = '/';
    return;
  }

  const pageContainer = document.getElementById('page');
  const navItems = document.querySelectorAll('.nav-item');
  const prevPath = currentPath;
  currentPath = path;

  // 1. Manage Visibility & Transitions
  const instances = pageContainer.querySelectorAll('.page-instance');
  instances.forEach(el => {
    if (el.dataset.path !== path) {
      el.classList.remove('active');
      // Hide after transition
      setTimeout(() => { if (!el.classList.contains('active')) el.style.display = 'none'; }, 300);
    }
  });

  // 2. Load or Show Page
  let activePageEl = pageCache.get(path);
  const isNew = !activePageEl;

  if (isNew) {
    activePageEl = document.createElement('div');
    activePageEl.className = 'page-instance';
    activePageEl.dataset.path = path;
    activePageEl.style.display = 'none'; // Prepare for transition
    pageContainer.appendChild(activePageEl);
    pageCache.set(path, activePageEl);
  }

  // Show navbar/bottom nav
  const navbar = document.getElementById('navbar');
  const bottomNav = document.getElementById('bottom-nav');
  if (path === '/login') {
    navbar.style.display = 'none';
    bottomNav.style.display = 'none';
    document.body.style.paddingTop = '0';
    document.body.style.paddingBottom = '0';
  } else {
    // Determine Navbar Configs
    let navConfig = { title: 'Toko Bersama App', showBack: false, onRefresh: false };
    if (path === '/') navConfig = { title: 'Dashboard', showBack: false, onRefresh: true };
    else if (path === '/products') navConfig = { title: 'Produk', showBack: false, onRefresh: false };
    else if (path === '/products/add') navConfig = { title: 'Tambah Produk', showBack: true, onRefresh: false };
    else if (path === '/products/edit') navConfig = { title: 'Edit Produk', showBack: true, onRefresh: false };
    else if (path === '/transactions') navConfig = { title: 'Transaksi', showBack: false, onRefresh: false };
    else if (path === '/reports') navConfig = { title: 'Laporan', showBack: false, onRefresh: true };
    else if (path === '/debts') navConfig = { title: 'Piutang', showBack: false, onRefresh: false };
    else if (path === '/profile') navConfig = { title: 'Profil', showBack: false, onRefresh: false };
    else if (path === '/stock-history') navConfig = { title: 'Riwayat Stok', showBack: true, onRefresh: false };
    else if (path === '/users') navConfig = { title: 'Aktivitas User', showBack: true, onRefresh: false };

    navbar.innerHTML = renderNavbar(navConfig);
    navbar.style.display = '';

    // Handle re-render badges
    const badges = {
      products: window._dashboardStats?.lowStockCount || 0,
      debts: window._dashboardStats?.overdueCount || 0
    };
    bottomNav.innerHTML = renderBottomNav(badges);
    bottomNav.style.display = '';

    document.body.style.paddingTop = '';
    document.body.style.paddingBottom = '';
  }

  // 3. Render and Init
  try {
    const page = routes[path] || routes['/'];

    if (isNew || path === '/products/edit' || path === '/products/add') {
      // Tampilkan skeleton SEBELUM fetch agar user tidak melihat layar kosong
      if (path !== '/login') {
        activePageEl.innerHTML = getSkeletonHTML(path);
        activePageEl.style.display = 'block';
        requestAnimationFrame(() => activePageEl.classList.add('active'));
      }

      // Fetch konten sesungguhnya (skeleton terlihat selama ini)
      // withPageTimeout() reject setelah 15 detik agar skeleton tidak menggantung selamanya
      const html = await withPageTimeout(page(query));
      activePageEl.innerHTML = html;

      // Initialize only on first render (or every time for forms)
      if (path === '/login') initLogin();
      if (path === '/' && window.initDashboard) window.initDashboard();
      if (path === '/products' && window.initProducts) window.initProducts();
      if (path === '/transactions' && window.initTransactions) window.initTransactions();
      if (path === '/reports' && window.initReports) window.initReports();
      if (path === '/debts' && window.initDebts) window.initDebts();
      if (path === '/profile' && window.initProfile) window.initProfile();
      if (path === '/stock-history' && window.initStockHistory) window.initStockHistory();
      if (path === '/users' && window.initUserActivity) window.initUserActivity();
      if ((path === '/products/add' || path === '/products/edit') && window.initProductForm) window.initProductForm();
    } else {
      // Cached pages — re-run init for data refresh
      if (path === '/' && window.initDashboard) window.initDashboard();
      if (path === '/products' && window.initProducts) window.initProducts(query);
    }

    // Trigger transition hanya jika belum aktif (halaman login atau cached page)
    if (!activePageEl.classList.contains('active')) {
      activePageEl.style.display = 'block';
      requestAnimationFrame(() => activePageEl.classList.add('active'));
    }

    if (path !== '/login' && isLoggedIn()) {
      initSession();
    }
  } catch (err) {
    const isTimeout = err.message === '__TIMEOUT__';
    const safeMsg = isTimeout
      ? 'Koneksi ke server terlalu lama.<br>Periksa jaringan Anda dan coba lagi.'
      : (err.message || 'Terjadi kesalahan')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');

    // Hapus dari cache agar retryCurrentPage re-fetch, bukan load dari cache lama yang error
    if (currentPath) pageCache.delete(currentPath);

    activePageEl.innerHTML = `
      <div style="display:flex;flex-direction:column;align-items:center;justify-content:center;padding:60px 20px;text-align:center;gap:16px;min-height:60vh;">
        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="color:var(--text-muted);flex-shrink:0;">
          ${isTimeout
        ? '<path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/>'
        : '<path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>'}
        </svg>
        <p style="color:var(--text-secondary);font-size:14px;line-height:1.6;max-width:280px;margin:0;">${safeMsg}</p>
        <button class="btn btn-outline" onclick="window.retryCurrentPage()">Coba Lagi</button>
      </div>
    `;
    activePageEl.style.display = 'block';
    activePageEl.classList.add('active');
  }

  updateActiveNav(path);
}

function updateActiveNav(path) {
  document.querySelectorAll('.nav-item').forEach(el => {
    el.classList.toggle('active', el.dataset.path === path);
  });
}

// Initialize app - langsung ke login tanpa discovery
async function initApp() {
  // Check if we're on localhost (development)
  const isLocalhost = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';

  if (isLocalhost) {
    // Development mode - use same host
    setApiServer('localhost', 3001);
    appInitialized = true;
    showMainApp();
    router();
    return;
  }

  // Cloudflare Tunnel auto-configuration - langsung connect ke domain
  // Admin domain dan API berada di server Express yang sama
  const adminDomains = ['admin.tbersamapalandan.my.id', 'admin.tbersama.my.id', 'app.tbersamapalandan.my.id'];
  if (adminDomains.includes(window.location.hostname)) {
    setApiServer(window.location.hostname, 443, 'https');
    appInitialized = true;
    showMainApp();
    router();
    return;
  }

  // Default: langsung connect ke hostname saat ini dengan HTTPS port 443
  setApiServer(window.location.hostname, 443, 'https');
  appInitialized = true;
  showMainApp();
  router();
}

function showMainApp() {
  document.getElementById('navbar').innerHTML = renderNavbar({ title: 'Toko Bersama App', showBack: false, onRefresh: false });
  document.getElementById('bottom-nav').innerHTML = renderBottomNav();
}

// Refresh halaman aktif: invalidate cache dan re-render
window.refreshCurrentPage = async () => {
  const pathToRefresh = currentPath;
  pageCache.delete(pathToRefresh);
  currentPath = null; // bypass same-path guard di router
  await router();
};

window.addEventListener('hashchange', router);
window.addEventListener('load', initApp);

// Register service worker for PWA
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('/sw.js').then(reg => {
    reg.addEventListener('updatefound', () => {
      const newWorker = reg.installing;
      newWorker.addEventListener('statechange', () => {
        if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
          showUpdatePrompt(() => window.location.reload());
        }
      });
    });
  }).catch(() => { });
}

function showUpdatePrompt(onConfirm) {
  const existing = document.getElementById('pwa-update-banner');
  if (existing) return;

  const banner = document.createElement('div');
  banner.id = 'pwa-update-banner';
  banner.innerHTML = `
    <span>Versi terbaru tersedia</span>
    <button id="btn-pwa-update">Muat Ulang</button>
    <button id="btn-pwa-dismiss">✕</button>
  `;
  document.body.appendChild(banner);

  document.getElementById('btn-pwa-update').addEventListener('click', () => {
    banner.remove();
    onConfirm();
  });
  document.getElementById('btn-pwa-dismiss').addEventListener('click', () => {
    banner.remove();
  });
}

// Global toast function
window.showToast = showToast;

// Global modal functions
window.openModal = (modalId) => {
  const modal = document.getElementById(modalId);
  if (modal) {
    modal.classList.add('open');
    document.body.classList.add('modal-open');
    modal.addEventListener('click', (e) => {
      if (e.target === modal) window.closeModal(modalId);
    }, { once: true });
  }
};

window.closeModal = (modalId) => {
  document.getElementById(modalId)?.classList.remove('open');
  document.body.classList.remove('modal-open');
};

// Close modal on overlay click
document.addEventListener('click', (e) => {
  if (e.target.classList.contains('modal-overlay')) {
    e.target.classList.remove('open');
    document.body.classList.remove('modal-open');
  }
});

// ─── Network Status Indicator ──────────────────────────────
function updateOnlineStatus() {
  const isOnline = navigator.onLine;
  document.body.classList.toggle('offline-mode', !isOnline);

  if (!isOnline) {
    showToast('Koneksi terputus. Beberapa fitur mungkin tidak tersedia.', 'warning', 5000);
  } else {
    // Hanya tampilkan toast "terpulihkan" jika sebelumnya offline
    if (document.body.classList.contains('was-offline')) {
      showToast('Koneksi terpulihkan', 'success', 2500);
    }
  }
  document.body.classList.toggle('was-offline', !isOnline);
}

window.addEventListener('online', updateOnlineStatus);
window.addEventListener('offline', updateOnlineStatus);
