// Reports Page dengan Chart.js
// Visualisasi laporan penjualan, kategori, dan metode pembayaran

import { renderSalesChart, renderPaymentChart, destroyChart } from '../components/charts.js';
import { fetchStats } from '../services/api.js';
import { formatCurrency, formatDate } from '../utils/format.js';

let salesChart = null;
let paymentChart = null;

export async function ReportsPage() {
  // Fetch data
  let stats;
  try {
    stats = await fetchStats();
  } catch (err) {
    return `
      <div class="page reports-page">
        <div class="error-state">
          <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
            <circle cx="12" cy="12" r="10"/>
            <line x1="12" y1="8" x2="12" y2="12"/>
            <line x1="12" y1="16" x2="12.01" y2="16"/>
          </svg>
          <p>Gagal memuat laporan: ${err.message}</p>
          <button class="btn btn-primary" onclick="window.refreshCurrentPage()">Coba Lagi</button>
        </div>
      </div>
    `;
  }

  const weekSales = stats.weekSales || [];
  const totalWeek = weekSales.reduce((sum, d) => sum + d.amount, 0);
  
  return `
    <div class="page reports-page">
      <div class="page-header">
        <h2 class="page-title">Laporan</h2>
      </div>

      <!-- Period Selector -->
      <div class="period-selector">
        <button class="period-btn active" data-period="week">7 Hari</button>
        <button class="period-btn" data-period="month">30 Hari</button>
      </div>

      <!-- Sales Trend Chart -->
      <div class="chart-card">
        <div class="chart-header">
          <h3>Tren Penjualan</h3>
          <span class="chart-total">${formatCurrency(totalWeek)}</span>
        </div>
        <div class="chart-container">
          <canvas id="salesChart"></canvas>
        </div>
      </div>

      <!-- Payment Methods -->
      <div class="chart-card">
        <div class="chart-header">
          <h3>Metode Pembayaran</h3>
        </div>
        <div class="chart-container" style="height: 250px;">
          <canvas id="paymentChart"></canvas>
        </div>
      </div>

      <!-- Quick Stats -->
      <div class="stats-grid">
        <div class="stat-box">
          <span class="stat-label">Total Transaksi</span>
          <span class="stat-value">${stats.today_count || 0}</span>
        </div>
        <div class="stat-box">
          <span class="stat-label">Rata-rata</span>
          <span class="stat-value">${formatCurrency(stats.today_average || 0)}</span>
        </div>
        <div class="stat-box">
          <span class="stat-label">Produk Terjual</span>
          <span class="stat-value">${stats.today_items || 0}</span>
        </div>
        <div class="stat-box">
          <span class="stat-label">Piutang</span>
          <span class="stat-value">${formatCurrency(stats.debt_total_outstanding || 0)}</span>
        </div>
      </div>
    </div>
  `;
}

// Expose ke window untuk dipanggil dari main.js
window.initReports = initReports;

export async function initReports() {
  // Cleanup existing charts
  destroyChart(salesChart);
  destroyChart(paymentChart);

  // Get data
  let stats;
  try {
    stats = await fetchStats();
  } catch (err) {
    return;
  }

  // Delay sedikit untuk memastikan DOM sudah siap
  setTimeout(() => {
    // Render Sales Chart
    const salesCanvas = document.getElementById('salesChart');
    if (salesCanvas && stats.weekSales && stats.weekSales.length > 0) {
      try {
        salesChart = renderSalesChart(salesCanvas, stats.weekSales);
      } catch (e) {
        // Chart error - tampilkan placeholder
        salesCanvas.parentElement.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">Grafik tidak dapat ditampilkan</div>';
      }
    }

    // Render Payment Chart
    const paymentCanvas = document.getElementById('paymentChart');
    if (paymentCanvas) {
      const paymentData = {
        cash: (stats.todaySales || 0) * 0.6,
        transfer: (stats.todaySales || 0) * 0.2,
        qris: (stats.todaySales || 0) * 0.15,
        debit: (stats.todaySales || 0) * 0.05
      };
      try {
        paymentChart = renderPaymentChart(paymentCanvas, paymentData);
      } catch (e) {
        paymentCanvas.parentElement.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted)">Grafik tidak dapat ditampilkan</div>';
      }
    }
  }, 100);

  // Period selector handler
  document.querySelectorAll('.period-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      document.querySelectorAll('.period-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });
}

// Expose ke window untuk dipanggil dari main.js
window.initReports = initReports;
