export function renderNavbar(config = {}) {
  const title = config.title || 'Toko Bersama App';
  const showBack = config.showBack === true;
  const onRefresh = config.onRefresh === true;

  const left = showBack ? `
    <button class="navbar-back" onclick="window.history.back()" aria-label="Kembali">
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
        <path d="M15 18l-6-6 6-6"/>
      </svg>
    </button>
  ` : '<div></div>';

  const right = onRefresh ? `
    <button class="navbar-action" onclick="window.refreshCurrentPage?.()" aria-label="Segarkan">
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M4 4v5h5M20 20v-5h-5M5 19a9 9 0 0115-6.7M19 5a9 9 0 01-15 6.7"/>
      </svg>
    </button>
  ` : '<div></div>';

  return `
    <div class="navbar">
      ${left}
      <h1 class="navbar-title">${title}</h1>
      ${right}
    </div>
  `;
}
