import { fetchTransactions, fetchTransactionById, voidTransaction, fetchPaymentHistory } from '../services/api.js';
import { formatCurrency, formatDate, renderEmptyState, escapeHtml } from '../utils/format.js';

let transactions = [];
let currentFilter = { status: 'all', dateFrom: '', dateTo: '', search: '' };
let selectedTx = null;

export async function TransactionsPage() {
  // Default filter to today's date (local timezone, not UTC)
  const now = new Date();
  const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
  currentFilter.dateFrom = today;
  currentFilter.dateTo = today;

  transactions = await fetchTransactions(currentFilter);

  return `
    <div class="page transactions-page">
      <h2 class="page-title">Transaksi</h2>

      <div class="search-bar">
        <input type="text" id="tx-search" placeholder="Cari ID atau nama customer..." class="search-input">
      </div>

      <div class="date-presets">
        <button class="preset-btn active" data-preset="today">Hari Ini</button>
        <button class="preset-btn" data-preset="yesterday">Kemarin</button>
        <button class="preset-btn" data-preset="week">7 Hari</button>
        <button class="preset-btn" data-preset="month">Bulan Ini</button>
      </div>

      <div class="date-filter">
        <input type="date" id="date-from" class="date-input" value="${today}">
        <span class="date-separator">-</span>
        <input type="date" id="date-to" class="date-input" value="${today}">
      </div>

      <div class="filter-chips">
        <button class="chip active" data-status="all">Semua</button>
        <button class="chip" data-status="lunas">Lunas</button>
        <button class="chip" data-status="pending">Pending</button>
        <button class="chip" data-status="hutang">Hutang</button>
        <button class="chip" data-status="cicilan">Cicilan</button>
        <button class="chip" data-status="void">Void</button>
      </div>

      <div class="tx-summary">
        <div class="summary-item">
          <span class="summary-label">Total</span>
          <span class="summary-value" id="tx-total">${formatCurrency(calcTotal(transactions))}</span>
        </div>
        <div class="summary-item">
          <span class="summary-label">Transaksi</span>
          <span class="summary-value" id="tx-count">${transactions.length}</span>
        </div>
      </div>

      <div class="compact-list" id="tx-list">
        ${renderTransactionList(transactions)}
      </div>

      <!-- Transaction Detail Modal -->
      <div class="modal-overlay" id="tx-detail-modal">
        <div class="product-modal-card modal-lg">
          <div class="modal-header">
            <h3 class="modal-title">Detail Transaksi</h3>
            <button class="modal-close" onclick="closeModal('tx-detail-modal')">&times;</button>
          </div>
          <div class="modal-body" id="tx-detail-content">
            <!-- Filled by JS -->
          </div>
          <div class="modal-footer" id="tx-detail-footer">
            <!-- Filled by JS -->
          </div>
        </div>
      </div>

      <!-- Void Modal -->
      <div class="modal-overlay" id="void-modal">
        <div class="product-modal-card">
          <div class="modal-header">
            <h3 class="modal-title">Void Transaksi</h3>
            <button class="modal-close" onclick="closeModal('void-modal')">&times;</button>
          </div>
          <div class="modal-body">
            <p>Apakah Anda yakin ingin membatalkan transaksi ini?</p>
            <div class="form-group">
              <label>Alasan pembatalan</label>
              <textarea id="void-reason" rows="3" placeholder="Masukkan alasan..." required></textarea>
            </div>
          </div>
          <div class="modal-footer">
            <button class="btn btn-outline" onclick="closeModal('void-modal')">Batal</button>
            <button class="btn btn-danger" id="btn-confirm-void">Void Transaksi</button>
          </div>
        </div>
      </div>
    </div>
  `;
}

function calcTotal(txs) {
  return txs
    .filter(t => t.status !== 'void')
    .reduce((sum, t) => sum + t.total, 0);
}

function renderTransactionList(items) {
  if (items.length === 0) {
    return renderEmptyState(
      `<svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>`,
      'Tidak ada transaksi pada periode ini',
      null, null
    );
  }
  return items.map(tx => {
    const statusConfig = {
      lunas: { class: 'success', label: 'Lunas' },
      pending: { class: 'info', label: 'Pending' },
      hutang: { class: 'warning', label: 'Hutang' },
      cicilan: { class: 'purple', label: 'Cicilan' },
      void: { class: 'danger', label: 'Void' }
    };
    const status = statusConfig[tx.status] || statusConfig.lunas;

    // Render items if available
    const itemsHtml = tx.itemDetails?.map(item => `
      <div class="tx-item-row">
        <span class="tx-item-name">${escapeHtml(item.name || item.product_name)}</span>
        <span class="tx-item-qty">${item.qty || item.quantity}x</span>
        <span class="tx-item-price">${formatCurrency(item.subtotal || (item.price * (item.qty || item.quantity)))}</span>
      </div>
    `).join('') || '<div class="tx-items-loading">Memuat...</div>';

    return `
      <div class="tx-card status-${tx.status} ${tx.status === 'void' ? 'voided' : ''}" data-id="${tx.id}">
        <div class="tx-card-header" onclick="toggleTxExpand('${tx.id}')">
          <div class="tx-card-main">
            <div class="tx-card-id">${escapeHtml(tx.invoiceNumber) || '#' + tx.id}</div>
            <div class="tx-card-info">
              ${escapeHtml(tx.customerName) || 'Walk-in'} • ${tx.items} item • ${formatDate(tx.date)}
            </div>
          </div>
          <div class="tx-card-end">
            <div class="tx-card-total">${formatCurrency(tx.total)}</div>
            <span class="badge badge-${status.class}">${status.label}</span>
          </div>
          <div class="tx-expand-icon">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
              <path d="M6 9l6 6 6-6"/>
            </svg>
          </div>
        </div>
        <div class="tx-card-body" id="tx-body-${tx.id}">
          <div class="tx-items-list">
            ${itemsHtml}
          </div>
          <div class="tx-card-footer">
            <button class="btn btn-sm btn-outline" onclick="showTxDetail('${tx.id}')">Detail</button>
            ${tx.status !== 'void' ? `<button class="btn btn-sm btn-outline btn-danger" onclick="showVoidModalFor('${tx.id}')">Void</button>` : ''}
          </div>
        </div>
      </div>
    `;
  }).join('');
}

window.showTxDetail = async (id) => {
  selectedTx = await fetchTransactionById(id);
  if (!selectedTx) return;

  const statusConfig = {
    lunas: { class: 'success', label: 'Lunas' },
    pending: { class: 'info', label: 'Pending' },
    hutang: { class: 'warning', label: 'Hutang' },
    cicilan: { class: 'purple', label: 'Cicilan' },
    void: { class: 'danger', label: 'Void' }
  };
  const status = statusConfig[selectedTx.status] || statusConfig.lunas;

  // Items list — handle both camelCase (mapped) and snake_case (raw DB) field names
  const itemsList = selectedTx.itemDetails?.map(item => `
    <div class="item-row">
      <div class="item-name">${escapeHtml(item.name || item.product_name)}</div>
      <div class="item-qty">${item.qty || item.quantity}x ${formatCurrency(item.price)}</div>
      <div class="item-subtotal">${formatCurrency(item.subtotal)}</div>
    </div>
  `).join('') || '<div class="empty-state small">Data item tidak tersedia</div>';

  // Payment history
  let paymentSection = '';
  if (selectedTx.paymentHistory && selectedTx.paymentHistory.length > 0) {
    const paymentList = selectedTx.paymentHistory.map(p => `
      <div class="payment-row">
        <div class="payment-info">
          <div class="payment-date">${p.date}</div>
          <div class="payment-method">${p.method} - ${escapeHtml(p.receivedBy)}</div>
          ${p.notes ? `<div class="payment-notes">${escapeHtml(p.notes)}</div>` : ''}
        </div>
        <div class="payment-amount">${formatCurrency(p.amount)}</div>
      </div>
    `).join('');

    paymentSection = `
      <div class="detail-section">
        <h4 class="section-title">Riwayat Pembayaran</h4>
        <div class="payment-list">
          ${paymentList}
        </div>
      </div>
    `;
  }

  // Void info
  let voidSection = '';
  if (selectedTx.status === 'void') {
    voidSection = `
      <div class="void-info">
        <div class="void-label">Dibatalkan</div>
        <div class="void-reason">${escapeHtml(selectedTx.voidReason) || '-'}</div>
        <div class="void-meta">${selectedTx.voidedAt} oleh ${escapeHtml(selectedTx.voidedBy)}</div>
      </div>
    `;
  }

  document.getElementById('tx-detail-content').innerHTML = `
    <div class="detail-section">
      <div class="detail-header">
        <h4 class="detail-name">${escapeHtml(selectedTx.invoiceNumber) || '#' + selectedTx.id}</h4>
        <span class="badge badge-${status.class}">${status.label}</span>
      </div>
      <div class="detail-info">
        <div class="detail-row">
          <span class="detail-label">Tanggal</span>
          <span class="detail-value">${selectedTx.date}</span>
        </div>
        <div class="detail-row">
          <span class="detail-label">Kasir</span>
          <span class="detail-value">${escapeHtml(selectedTx.cashierName)}</span>
        </div>
        ${selectedTx.customerName ? `
          <div class="detail-row">
            <span class="detail-label">Customer</span>
            <span class="detail-value">${escapeHtml(selectedTx.customerName)}</span>
          </div>
        ` : ''}
        ${selectedTx.dueDate ? `
          <div class="detail-row">
            <span class="detail-label">Jatuh Tempo</span>
            <span class="detail-value">${selectedTx.dueDate}</span>
          </div>
        ` : ''}
        <div class="detail-row">
          <span class="detail-label">Metode Pembayaran</span>
          <span class="detail-value">${escapeHtml(selectedTx.paymentMethod) || '-'}</span>
        </div>
      </div>
    </div>
    
    ${selectedTx.paymentNotes ? `
    <div class="detail-section tx-notes">
        <div class="tx-notes-label">Catatan</div>
        <div class="tx-notes-text">${escapeHtml(selectedTx.paymentNotes)}</div>
    </div>
    ` : ''}

    <div class="detail-section">
      <h4 class="section-title">Item (${selectedTx.items})</h4>
      <div class="items-list">
        ${itemsList}
      </div>
      <div class="items-total">
        <div class="total-row">
          <span>Total</span>
          <span>${formatCurrency(selectedTx.total)}</span>
        </div>
        <div class="total-row">
          <span>Dibayar</span>
          <span>${formatCurrency(selectedTx.amountPaid)}</span>
        </div>
        ${selectedTx.remainingBalance ? `
          <div class="total-row highlight">
            <span>Sisa</span>
            <span>${formatCurrency(selectedTx.remainingBalance)}</span>
          </div>
        ` : ''}
        ${selectedTx.change > 0 ? `
          <div class="total-row">
            <span>Kembalian</span>
            <span>${formatCurrency(selectedTx.change)}</span>
          </div>
        ` : ''}
      </div>
    </div>

    ${paymentSection}
    ${voidSection}
  `;

  // Footer buttons
  let footerButtons = '<button class="btn" onclick="closeModal(\'tx-detail-modal\')">Tutup</button>';
  if (selectedTx.status !== 'void') {
    footerButtons = `
      <button class="btn btn-outline btn-danger" onclick="showVoidModal()">Void</button>
      ${footerButtons}
    `;
  }
  document.getElementById('tx-detail-footer').innerHTML = footerButtons;

  openModal('tx-detail-modal');
};

window.showVoidModal = () => {
  closeModal('tx-detail-modal');
  document.getElementById('void-reason').value = '';
  openModal('void-modal');
};

window.showVoidModalFor = (id) => {
  const numId = parseInt(id);
  selectedTx = transactions.find(t => t.id === numId);
  document.getElementById('void-reason').value = '';
  openModal('void-modal');
};

window.toggleTxExpand = async (id) => {
  const card = document.querySelector(`.tx-card[data-id="${id}"]`);
  const body = document.getElementById(`tx-body-${id}`);

  if (!card || !body) return;

  const isExpanded = card.classList.contains('expanded');

  // Close all other expanded cards
  document.querySelectorAll('.tx-card.expanded').forEach(c => {
    c.classList.remove('expanded');
  });

  if (!isExpanded) {
    card.classList.add('expanded');

    // Load items if not already loaded
    const tx = transactions.find(t => String(t.id) === String(id));
    if (tx && !tx.itemDetails) {
      try {
        const fullTx = await fetchTransactionById(id);
        tx.itemDetails = fullTx.itemDetails;

        // Re-render items
        const itemsHtml = tx.itemDetails?.map(item => `
          <div class="tx-item-row">
            <span class="tx-item-name">${item.name || item.product_name}</span>
            <span class="tx-item-qty">${item.qty || item.quantity}x</span>
            <span class="tx-item-price">${formatCurrency(item.subtotal || (item.price * (item.qty || item.quantity)))}</span>
          </div>
        `).join('') || '<div class="empty-state small">Tidak ada item</div>';

        body.querySelector('.tx-items-list').innerHTML = itemsHtml;
      } catch (err) {
        console.error('Error loading transaction items:', err);
        body.querySelector('.tx-items-list').innerHTML = '<div class="empty-state small">Gagal memuat item</div>';
      }
    }
  }
};

window.initTransactions = () => {
  const chips = document.querySelectorAll('.chip');
  const dateFrom = document.getElementById('date-from');
  const dateTo = document.getElementById('date-to');
  const searchInput = document.getElementById('tx-search');
  const btnVoid = document.getElementById('btn-confirm-void');

  // Filter chips
  chips.forEach(chip => {
    chip.addEventListener('click', async () => {
      chips.forEach(c => c.classList.remove('active'));
      chip.classList.add('active');
      currentFilter.status = chip.dataset.status;
      await refreshTransactions();
    });
  });

  // Date preset buttons
  function getDateRange(preset) {
    const now = new Date();
    const pad = n => String(n).padStart(2, '0');
    const fmt = d => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
    const today = fmt(now);
    switch (preset) {
      case 'today': return { from: today, to: today };
      case 'yesterday': {
        const y = new Date(now); y.setDate(y.getDate() - 1);
        const yd = fmt(y); return { from: yd, to: yd };
      }
      case 'week': {
        const w = new Date(now); w.setDate(w.getDate() - 6);
        return { from: fmt(w), to: today };
      }
      case 'month': {
        const m = new Date(now.getFullYear(), now.getMonth(), 1);
        return { from: fmt(m), to: today };
      }
      default: return { from: today, to: today };
    }
  }

  document.querySelectorAll('.preset-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      document.querySelectorAll('.preset-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      const range = getDateRange(btn.dataset.preset);
      if (dateFrom) dateFrom.value = range.from;
      if (dateTo) dateTo.value = range.to;
      currentFilter.dateFrom = range.from;
      currentFilter.dateTo = range.to;
      await refreshTransactions();
    });
  });

  // Date filter — clear preset active saat input manual
  dateFrom?.addEventListener('change', async () => {
    document.querySelectorAll('.preset-btn').forEach(b => b.classList.remove('active'));
    currentFilter.dateFrom = dateFrom.value;
    await refreshTransactions();
  });

  dateTo?.addEventListener('change', async () => {
    document.querySelectorAll('.preset-btn').forEach(b => b.classList.remove('active'));
    currentFilter.dateTo = dateTo.value;
    await refreshTransactions();
  });

  // Search
  searchInput?.addEventListener('input', async (e) => {
    currentFilter.search = e.target.value;
    await refreshTransactions();
  });

  // Void confirm
  btnVoid?.addEventListener('click', async () => {
    if (!selectedTx) return;
    const reason = document.getElementById('void-reason').value.trim();
    if (!reason) {
      window.showToast?.('Masukkan alasan pembatalan', 'warning');
      return;
    }

    await voidTransaction(selectedTx.id, reason);
    closeModal('void-modal');
    await refreshTransactions();
  });
};

async function refreshTransactions() {
  transactions = await fetchTransactions(currentFilter);
  document.getElementById('tx-list').innerHTML = renderTransactionList(transactions);
  document.getElementById('tx-total').textContent = formatCurrency(calcTotal(transactions));
  document.getElementById('tx-count').textContent = transactions.length;
}
