import { fetchProducts, fetchCategories, createProduct, updateProduct, generateBarcode, createCategory, fetchSettings, fetchCurrentUser } from '../services/api.js';
import { formatInputNumber, parseInputNumber, setupNumberInput, escapeHtml } from '../utils/format.js';

let categories = [];
let editingProduct = null;
let defaultMargin = 10.5;
let isManualCost = false;

export async function ProductFormPage(query) {
  const productId = query.id ? parseInt(query.id) : null;
  const isEdit = !!productId;

  // Fetch settings for default margin
  try {
    const settings = await fetchSettings();
    if (settings.default_margin_percent) {
      defaultMargin = parseFloat(settings.default_margin_percent);
    }
  } catch (e) {
    console.warn('Using default margin 10.5%');
  }

  // Fetch categories for dropdown
  categories = await fetchCategories();
  const categoryOptions = categories.map(c => `<option value="${escapeHtml(c.name)}">`).join('');

  // Common units
  const commonUnits = ['pcs', 'kg', 'gram', 'liter', 'ml', 'pack', 'box', 'lusin', 'dus', 'karton', 'sachet', 'botol', 'kaleng', 'bungkus', 'pasang', 'set', 'rim', 'roll', 'meter', 'lembar'];
  const unitOptions = commonUnits.map(u => `<option value="${escapeHtml(u)}">`).join('');

  // If editing, fetch product data
  if (isEdit) {
    const products = await fetchProducts();
    editingProduct = products.find(p => p.id === productId);

    if (!editingProduct) {
      return renderErrorState(productId);
    }

    // Determine manual cost mode based on data
    if (editingProduct.margin_mode === 'manual') {
      isManualCost = true;
    } else if (editingProduct.margin_mode === 'auto') {
      isManualCost = false;
    } else {
      // Logic for legacy data: check if cost matches formula
      const price = editingProduct.price || 0;
      const currentCost = editingProduct.cost || 0;
      const multiplier = 1 - (defaultMargin / 100);
      const calculatedCost = Math.round(price * multiplier);
      // Tolerance of 100 rupiah
      isManualCost = Math.abs(currentCost - calculatedCost) > 100;
    }
  } else {
    editingProduct = null;
    isManualCost = false; // Default auto for new products
  }

  const title = isEdit ? 'Edit Produk' : 'Tambah Produk';

  return `
    <div class="page product-form-page">
      <div class="page-header">
        <button class="btn btn-icon" id="btn-back" aria-label="Kembali">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <h2 class="page-title">${title}</h2>
      </div>

      <div class="form-container">
        <form id="product-form" class="product-form">
          <div class="form-section">
            <h3 class="section-title">Informasi Dasar</h3>
            
            <div class="form-grup-wrapper">
              <div class="form-group full-width">
                <label>Nama Produk <span class="required">*</span></label>
                <input type="text" id="product-name" required placeholder="Contoh: Indomie Goreng" 
                  value="${isEdit ? escapeHtml(editingProduct.name) : ''}" class="input-lg">
              </div>

              <div class="form-group half-width">
                <label>Kategori <span class="required">*</span></label>
                <div class="input-with-icon">
                   <input type="text" id="product-category" list="category-list" placeholder="Pilih kategori..." 
                    autocomplete="off" required value="${isEdit ? escapeHtml(editingProduct.category || '') : ''}">
                   <datalist id="category-list">${categoryOptions}</datalist>
                   <svg class="icon-right" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M19 9l-7 7-7-7"/></svg>
                </div>
              </div>

              <div class="form-group half-width">
                <label>Satuan <span class="required">*</span></label>
                <input type="text" id="product-unit" list="unit-list" placeholder="pcs" 
                  autocomplete="off" required value="${isEdit ? escapeHtml(editingProduct.unit || 'pcs') : ''}">
                <datalist id="unit-list">${unitOptions}</datalist>
              </div>
            </div>
          </div>

          <div class="form-section">
            <h3 class="section-title">Harga & Stok</h3>
            
            <div class="form-grup-wrapper">
              <div class="form-group half-width">
                <label>Harga Jual <span class="required">*</span></label>
                <div class="input-prefix">
                  <span>Rp</span>
                  <input type="text" id="product-price" inputmode="numeric" required placeholder="0" autocomplete="off"
                    value="${isEdit ? formatInputNumber(editingProduct.price) : ''}">
                </div>
              </div>

              <div class="form-group half-width">
                <div class="label-with-action">
                  <label>Harga Modal</label>
                  <label class="toggle-switch">
                    <input type="checkbox" id="cost-manual-toggle" ${isManualCost ? 'checked' : ''}>
                    <span class="toggle-slider"></span>
                    <span class="toggle-label">Manual</span>
                  </label>
                </div>
                <div class="input-prefix">
                  <span>Rp</span>
                  <input type="text" id="product-cost" inputmode="numeric" placeholder="0" autocomplete="off"
                    value="${isEdit && editingProduct.cost ? formatInputNumber(editingProduct.cost) : ''}"
                    ${!isManualCost ? 'readonly' : ''} class="${!isManualCost ? 'bg-gray' : ''}">
                </div>
                <small class="form-hint" id="cost-hint">
                  ${!isManualCost ? `Otomatis (Margin ${defaultMargin}%)` : 'Input manual'}
                </small>
              </div>

              <div class="form-group half-width">
                <label>Stok Awal ${isEdit ? '' : '<span class="required">*</span>'}</label>
                <input type="number" id="product-stock" ${isEdit ? 'disabled' : 'required'} placeholder="0"
                  value="${isEdit ? editingProduct.stock : ''}">
                ${isEdit ? '<small class="form-hint">Stok dikelola via riwayat</small>' : ''}
              </div>
            </div>
          </div>

          <div class="form-actions sticky-bottom">
            <button type="button" class="btn btn-lg btn-secondary" id="btn-cancel">Batal</button>
            <button type="submit" class="btn btn-lg btn-primary" id="btn-save">
              ${isEdit ? 'Simpan Perubahan' : 'Simpan Produk'}
            </button>
          </div>
        </form>
      </div>
    </div>
  `;
}

function renderErrorState(productId) {
  return `
    <div class="page product-form-page">
      <div class="page-header">
        <button class="btn btn-icon" onclick="window.location.hash='/products'" aria-label="Kembali ke Produk">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <h2 class="page-title">Error</h2>
      </div>
      <div class="empty-state">
        <p>Produk dengan ID ${productId} tidak ditemukan.</p>
        <button class="btn btn-primary" onclick="window.location.hash='/products'">Kembali</button>
      </div>
    </div>
  `;
}

// Helper: Get or create category
async function getOrCreateCategory(categoryName) {
  const existing = categories.find(c => c.name.toLowerCase() === categoryName.toLowerCase());
  if (existing) return existing.id;
  try {
    const newCat = await createCategory(categoryName);
    categories.push(newCat);
    return newCat.id;
  } catch (e) {
    console.error('Error creating category:', e);
    return null;
  }
}

// Helper: Calculate Cost
function calculateCost(price) {
  const multiplier = 1 - (defaultMargin / 100);
  return Math.round(price * multiplier);
}

// Helper: Get User Info
async function getUserInfo() {
  try {
    const user = await fetchCurrentUser();
    return { userId: user.id, userName: user.username };
  } catch (e) {
    return { userId: null, userName: 'System' };
  }
}

window.initProductForm = () => {
  const form = document.getElementById('product-form');
  const btnBack = document.getElementById('btn-back');
  const btnCancel = document.getElementById('btn-cancel');

  // Element references for logic
  const priceInput = document.getElementById('product-price');
  const costInput = document.getElementById('product-cost');
  const manualToggle = document.getElementById('cost-manual-toggle');
  const costHint = document.getElementById('cost-hint');

  // Setup formatting
  try {
    setupNumberInput('product-price');
    setupNumberInput('product-cost');
  } catch (e) { console.error(e); }

  // 1. Manual Toggle Logic
  manualToggle?.addEventListener('change', (e) => {
    isManualCost = e.target.checked;

    if (isManualCost) {
      costInput.readOnly = false;
      costInput.classList.remove('bg-gray');
      costHint.textContent = 'Input manual';
      costInput.focus();
    } else {
      costInput.readOnly = true;
      costInput.classList.add('bg-gray');
      costHint.textContent = `Otomatis (Margin ${defaultMargin}%)`;
      // Recalculate immediately
      const price = parseInputNumber(priceInput.value);
      if (price) {
        costInput.value = formatInputNumber(calculateCost(price));
      }
    }
  });

  // 2. Price Change Logic (Auto-calculate cost)
  priceInput?.addEventListener('input', (e) => {
    if (!isManualCost) {
      // We need raw value, but setupNumberInput formats it on input
      // So we parse the formatted value
      // Small delay to let formatting happen first might be safer, but sync works usually
      setTimeout(() => {
        const price = parseInputNumber(priceInput.value);
        if (price) {
          const cost = calculateCost(price);
          costInput.value = formatInputNumber(cost);
        } else {
          costInput.value = '';
        }
      }, 0);
    }
  });

  // Navigation
  const goBack = () => window.location.hash = '/products';
  btnBack?.addEventListener('click', goBack);
  btnCancel?.addEventListener('click', goBack);

  // Submission
  form?.addEventListener('submit', async (e) => {
    e.preventDefault();
    const btnSave = document.getElementById('btn-save');
    const originalText = btnSave.textContent;

    // UI Loading State
    btnSave.disabled = true;
    btnSave.textContent = 'Menyimpan...';

    try {
      const name = document.getElementById('product-name').value.trim();
      const price = parseInputNumber(priceInput.value);
      const cost = parseInputNumber(costInput.value) || 0;
      const stock = parseInt(document.getElementById('product-stock').value) || 0;
      const unit = document.getElementById('product-unit').value.trim().toLowerCase();
      const categoryName = document.getElementById('product-category').value.trim();

      if (!name || !price || !unit || !categoryName) {
        throw new Error('Mohon lengkapi field bertanda *');
      }

      const categoryId = await getOrCreateCategory(categoryName);

      const productData = {
        name,
        price,
        cost,
        unit,
        category_id: categoryId,
        margin_mode: isManualCost ? 'manual' : 'auto',
        userId: (await getUserInfo()).userId,
        userName: (await getUserInfo()).userName
      };

      if (editingProduct) {
        await updateProduct(editingProduct.id, productData);
        // Show lightweight toast or alert
        alert('Produk berhasil diperbarui');
      } else {
        const barcode = await generateBarcode();
        await createProduct({ ...productData, barcode, stock });
        alert('Produk berhasil ditambahkan');
      }

      goBack();

    } catch (error) {
      console.error(error);
      alert(error.message);
      btnSave.disabled = false;
    }
  });
};



