import { fetchUsers } from '../services/api.js';
import { formatDate, escapeHtml } from '../utils/format.js';
import { getSession } from '../utils/session.js';

let users = [];

export async function UserActivityPage() {
  const session = getSession();
  if (session?.role !== 'admin') {
    window.location.hash = '/';
    return '<div></div>';
  }

  users = await fetchUsers();

  const roleLabels = {
    admin: 'Administrator',
    supervisor: 'Supervisor',
    cashier: 'Kasir'
  };

  const userCards = users.map(user => {
    // Extract initials safely, prefer fullName then username
    const initials = escapeHtml(user.fullName || user.username || 'U').charAt(0).toUpperCase();

    return `
      <div class="section-card user-activity-card">
        <div class="user-card-header">
          <div class="user-avatar">${initials}</div>
          <div class="user-main-info">
            <div class="user-name">${escapeHtml(user.fullName || user.username)}</div>
            <div class="user-role-badge ${user.role}">${roleLabels[user.role] || user.role}</div>
          </div>
        </div>
        <div class="user-card-details">
          <div class="detail-row">
            <span class="detail-label">Username</span>
            <span class="detail-value">@${escapeHtml(user.username)}</span>
          </div>
          <div class="detail-row">
            <span class="detail-label">Login Terakhir</span>
            <span class="detail-value">${user.lastLogin ? formatDate(user.lastLogin) : 'Belum pernah login'}</span>
          </div>
        </div>
      </div>
    `;
  }).join('');

  return `
    <div class="page user-activity-page">
      <div class="page-header">
        <button class="btn-back" onclick="window.history.back()">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M19 12H5M12 19l-7-7 7-7"/>
          </svg>
        </button>
        <h2 class="page-title">Aktivitas Login</h2>
      </div>

      <div class="activity-list">
        ${userCards}
      </div>
    </div>
  `;
}

window.initUserActivity = () => {
  // Initialization logic if needed
};
