import { fetchStockHistory } from '../services/api.js';
import { formatDate, formatCurrency, escapeHtml } from '../utils/format.js';

export async function StockHistoryPage() {
  const history = await fetchStockHistory(null); // Fetch all history

  return `
    <div class="page stock-history-page">
      <div class="page-header">
        <button class="btn btn-icon" onclick="window.history.back()" aria-label="Kembali">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>
        <h2 class="page-title">Riwayat Stok</h2>
      </div>

      <div class="history-list full-page-list">
        ${renderHistoryList(history)}
      </div>
    </div>
  `;
}

function renderHistoryList(items) {
  if (items.length === 0) {
    return '<div class="empty-state">Belum ada riwayat perubahan stok</div>';
  }

  // Group by date
  const grouped = items.reduce((acc, item) => {
    const date = item.createdAt.split('T')[0];
    if (!acc[date]) acc[date] = [];
    acc[date].push(item);
    return acc;
  }, {});

  return Object.keys(grouped).sort().reverse().map(date => `
    <div class="history-group">
      <div class="history-date-header">${formatDate(date)}</div>
      ${grouped[date].map(h => {
    const typeLabel = {
      sale: 'Penjualan',
      manual: 'Manual',
      restock: 'Restok',
      adjustment: 'Koreksi',
      import: 'Import',
      initial: 'Stok Awal'
    };
    const typeClass = h.quantity > 0 ? 'positive' : 'negative';

    return `
          <div class="history-item">
            <div class="history-icon ${h.changeType}">
               ${getIconForType(h.changeType)}
            </div>
            <div class="history-content">
              <div class="history-title">${escapeHtml(h.productName)}</div>
              <div class="history-meta">
                ${typeLabel[h.changeType] || h.changeType} • ${escapeHtml(h.userName) || '-'}
                ${h.notes ? `<br><span class="history-notes">"${escapeHtml(h.notes)}"</span>` : ''}
              </div>
            </div>
            <div class="history-change ${typeClass}">
              ${h.quantity > 0 ? '+' : ''}${h.quantity}
            </div>
          </div>
        `;
  }).join('')}
    </div>
  `).join('');
}

function getIconForType(type) {
  if (type === 'sale') return '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"/></svg>';
  if (type === 'restock') return '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 4v16m-8-8h16"/></svg>';
  return '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>';
}
